INSERT INTO `academic_accounts` (`id`, `name`, `email`, `password`, `institution_type`, `logo`, `banner`, `description`, `website`, `phone`, `address`, `city`, `is_active`, `remember_token`, `created_at`, `updated_at`) VALUES
(2, 'Dar Al Kalima University', 'info@daralkalima.edu.ps', '$2y$12$iqqdcIjKDtq494thmE5wsuIw4D4/20QB.GruXQPnvscte3DlPwDy6', 'university', 'academic-accounts/academic_2_1770107858_logo.png', NULL, 'Dar Al-Kalima University is a Palestinian university specializing in arts, culture, and design. It is committed to graduating generations of creative young leaders through high-quality academic programs, while providing opportunities for lifelong learning and promoting a culture of entrepreneurship, scientific research, and community engagement.', 'https://www.daralkalima.edu.ps/ar', '+970227570289', 'Mureir Mountain, Bethlehem,', 'Bethlehem', 1, NULL, '2026-01-21 05:23:46', '2026-02-03 06:37:39'),
(3, 'Palestine Polytechnic University', 'info@ppu.edu', '$2y$12$I4k1cQv9fGi1wSm8Z/gIC.miRrECEz4ztarhlN2w2t.wN5q.ztiPG', 'university', NULL, NULL, 'Palestine Polytechnic University” in Hebron is a Palestinian public university that is committed to the laws of the Palestinian Ministry of Higher Education and Scientific Research. PPU is recognized with its membership in organizations including the Palestinian Higher Education Council, Union of Arab Universities, the Association of Islamic Universities, and the World University Federation. The university enjoys close cooperative relations with many Arab and international academic and civil society organizations', 'http://cap.ppu.edu/', '+97022233050', 'Palestine, Hebron, Dahiat albaladia', 'Hebron', 1, NULL, '2026-01-22 11:54:37', '2026-01-26 11:55:16');
