(3, 2, 'دورة النقش على النحاس', 'تعلن جامعة دار الكلمة مع وزراة الثقافة وبدعم من اليونسكو ضمن برنامج بالتيزانا لتطوير المنتات الحرفية للمشاركة في دورة تدريبية', 'فنون النقش على المعاد والتي تشمل النحاس هي احد العناصر المدرجة على القائمة التمثيلية للتراث الثقافي غير المادي بمنظمة اليونيسكو \r\nتهدف الدورة الى انتاج منتج مميزة بحرفة النقش على النحاس والمساعدة في تسويقه عبر منصة بالتيزانا\r\nسيحل المشاركون على شهاد مشاركة', 'academic-trainings/academic_training_1768982963.jpg', 'design', 'intermediate', 'hybrid', NULL, NULL, NULL, '2026-01-21', '2026-01-28', NULL, 'https://www.daralkalima.edu.ps/ar/news/1746769878', NULL, '[\"تخصص فنون\"]', NULL, 1, 22, 'approved', NULL, '2026-01-21 06:09:43', 194, '2026-01-21 06:09:23', '2026-01-26 14:41:04'),
(7, 2, 'tes', 'tes', 'testtesttesttesttesttesttesttesttesttesttesttesttesttesttesttesttesttest', 'academic-trainings/academic_training_1770015268.png', 'design', 'beginner', 'hybrid', NULL, '20', NULL, '2026-02-02', '2026-02-08', NULL, NULL, NULL, '[\"test\"]', NULL, 1, 0, 'rejected', 'modify it', NULL, 194, '2026-02-02 04:54:28', '2026-02-02 04:55:05'),
(8, 2, 'test', 'test', 'testtesttesttesttesttesttesttesttesttesttesttesttesttesttesttesttesttesttesttest', 'academic-trainings/academic_training_1770017864.png', 'design', 'beginner', 'online', NULL, '50', NULL, '2026-02-02', '2026-02-08', NULL, NULL, NULL, '[\"4th year\", \"Specialization Design\"]', NULL, 1, 6, 'approved', NULL, '2026-02-02 05:38:51', 194, '2026-02-02 05:37:44', '2026-02-04 21:54:23'),
(11, 2, 'test', 'test', 'test', 'academic-trainings/academic_training_1770707300.jpg', 'design', 'beginner', 'hybrid', NULL, 'Free', NULL, '2026-02-10', '2026-02-10', NULL, NULL, 10, '[\"test\"]', NULL, 1, 1, 'approved', NULL, '2026-02-10 05:35:47', 194, '2026-02-10 05:08:20', '2026-02-10 05:37:21');
INSERT INTO `academic_workshops` (`id`, `academic_account_id`, `title`, `short_description`, `description`, `image`, `category`, `location_type`, `location`, `price`, `duration`, `workshop_date`, `start_time`, `end_time`, `max_participants`, `requirements`, `tools_provided`, `has_certificate`, `views_count`, `approval_status`, `rejection_reason`, `approved_at`, `approved_by`, `created_at`, `updated_at`) VALUES
(1, 3, 'دعوة لحضور ورشة عمل بعنوان فنون المستقبل: دمج التصميم بالذكاء الاصطناعي', NULL, 'تنظم جامعة بوليتكنك فلسطين ورشة عمل إلكترونية بالتنسيق بين كلية الفنون والتصميم ومركز الذكاء الاصطناعي في الجامعة. يُدير الجلسة كل من عميد كلية الفنون والتصميم الدكتور عبد الفتاح النجار ومدير مركز الذكاء الاصطناعي الدكتور هاني صلاح.\r\nتتناول ورشة العمل، موضوع التصميم باستخدام الذكاء الاصطناعي وتستعرض التحديات المتعلقة به. سيتولى قيادة هذه الورشة الخبيرة في المجال والمصممة المحترفة آية عطية عابد من جمهورية مصر العربية، التي تمتلك خبرة تمتد لأكثر من 8 سنوات في مجال التصميم.\r\nالدعوة مفتوحة لـ:', 'academic-workshops/academic_workshop_1769090394.png', NULL, NULL, NULL, NULL, NULL, '2026-01-22', '10:00:00', '13:00:00', NULL, NULL, NULL, 0, 19, 'approved', NULL, '2026-01-22 12:00:16', 194, '2026-01-22 11:59:54', '2026-02-20 11:55:18');
