(102, 'Nayef Hammouri', 'Creative Director', 'nayef.hammouri@hotmail.com', 1, 'profiles/profile_102.png', NULL, NULL, 'I\'m Nayef — a video editor and AI visual creator with 10+ years of experience crafting impactful videos, motion graphics, and AI-generated visuals. I transform ideas into engaging content for brands, creators, and e-commerce. Skilled in DaVinci Resolve, Adobe Premiere, After Effects, Photoshop, Illustrator, and Lightroom. Experienced with Runway AI, Kling, Midjourney, Veo 3, and more. Always open to new projects—let’s create visuals that stand out.', NULL, 1, 1, 1, 1, NULL, 0, 0, 0, 0, 1, 0, 0, 15, 0, 0, NULL, '$2y$12$mO.hphil39tId5AKeXAoSuT7HIfBGrN6dWNPMgBFY7ScK.ifMgVe2', NULL, '2025-12-04 21:03:01', '2026-02-09 22:41:13', 'Nayef', 'Hammouri', 'Designer', 'Visual Arts', 'Nayef Hammouri', 'Creative Director', '0562121111', 'PS', 'Ramallah and Al-Bireh', 'Ramallah, Al-Tira', '10+', NULL, NULL, NULL, NULL, 1),
(103, 'Abdallah Salem', 'Multimedia & UI/UX Designer | Freelance', 'abdsalem499@gmail.com', 1, 'profiles/profile_103.png', NULL, NULL, 'I am a Palestinian Multimedia Technology student and freelance multimedia & UI/UX designer based in Gaza, with 3–5 years of experience in branding, web and digital product design. I create visual identities, websites, social media visuals and presentations for companies, startups and NGOs. I am passionate about human-centered design, clear storytelling and using design to support education, culture and social impact projects from Palestine to the world.', NULL, 1, 1, 1, 1, NULL, 0, 0, 0, 0, 1, 0, 0, 16, 0, 5, NULL, '$2y$12$6Ds/kkKWjfgMWGwr9KelOOWdDnB3THb1DuHYbBImVNuRzqN4G6eLe', NULL, '2025-12-05 06:15:14', '2026-02-13 22:23:05', 'Abdallah', 'Salem', 'designer', 'Graphic Designer', 'AbdulDes – Creative Design Studio', 'Multimedia & UI/UX Designer | Freelance', '0592089686', 'PS', 'Gaza', 'Apt 1 Al-Dawli 6 Building, Tal Al-Hawa (near Radio & TV Junction), Gaza City, State of Palestine', '3-5', NULL, NULL, NULL, NULL, 1),
