(159, 'Dalal Carpentry and Furniture', 'Owner', 'saaedmohamad334@gmail.com', 1, 'profiles/profile_159.jpg', NULL, 'covers/hero_159.jpg', 'Dalal Carpentry & Furniture, based in Hebron, specializes in high-quality furniture and carpentry solutions. The company produces and designs home and office furniture, offering custom-made pieces tailored to clients’ needs. Dalal Carpentry & Furniture is committed to using the finest materials, ensuring durability and quality, while emphasizing innovative and elegant designs.', NULL, 1, 1, 1, 1, NULL, 0, 0, 0, 0, 1, 0, 0, 3, 0, 0, NULL, '$2y$12$mDNFHJIr3mm2bMmDEh1wnuXDkxTg0QjgYYslRzAGQTWGFfo4NB4sy', NULL, '2025-12-17 11:53:03', '2026-02-12 05:13:08', 'Dalal Carpentry', 'and Furniture', 'manufacturer', 'Furniture Manufacturer', 'منجره ومفروشات دلال', 'Owner', '0597733854', 'PS', 'Hebron', 'Hebron - Wadi Abu Katila', '10+', NULL, NULL, NULL, NULL, 1),
(162, 'Wasef Mutie Furniture', 'Owner', 'wasef@wasefurniture.com', 1, 'profiles/profile_162.png', NULL, 'covers/hero_162.jpeg', 'years of experience: over 50 years\r\nWasef Mutie Factory & Showroom is a leading name in woodworking and furniture manufacturing, built on a rich family legacy of craftsmanship that spans over 100 years of inherited carpentry expertise. Through continuous development and commitment to excellence, the factory has grown to become one of the largest woodworking manufacturers in the West Bank.\r\nThe factory operates with a wide range of state-of-the-art industrial machinery,', NULL, 1, 1, 1, 1, NULL, 0, 0, 0, 0, 1, 0, 0, 5, 0, 0, NULL, '$2y$12$mUSow5aoP04AZ3el8j5pZ.IkayA0gtxI8raLUvoXpXpd2IUAUOSbS', NULL, '2025-12-22 07:02:27', '2026-02-16 12:21:33', 'Wasef Mutie', 'Furniture', 'manufacturer', 'Furniture Manufacturer', 'Wasef Mutie Furniture', 'Owner', '0599201278', 'PS', 'Ramallah and Al-Bireh', 'Ramallah - Betionia', '10+ years', NULL, NULL, NULL, NULL, 1),
(163, 'Oznil Mobilya', 'Owner', 'contact@oznil.ps', 1, 'profiles/profile_163.png', NULL, 'covers/hero_163.jpeg', 'Oznil Mobilya is a leading furniture manufacturer and retailer in Bethlehem, specializing in high-quality home furnishings and custom-made pieces. Combining skilled craftsmanship with modern manufacturing techniques, the company delivers durable, stylish, and functional furniture. From design to production, Oznil Mobilya ensures every piece meets strict quality standards while offering unique solutions to fit a variety of tastes and needs.', NULL, 1, 1, 1, 1, NULL, 0, 0, 0, 0, 1, 0, 0, 20, 0, 0, NULL, '$2y$12$uyHWpCQ.n5sx3Gz5o0BnneA6k51Xjefkz9ltSbXaApk.Opp0LZRP6', 'IygXSFJfWHLDogHCMVp8ut42lkBNzVh2bGUXP7jSiDIo49fgbj66e7T1OcLf', '2025-12-22 10:03:10', '2026-02-20 10:37:39', 'Oznil', 'Mobilya', 'manufacturer', 'Furniture Manufacturer', 'Oznil Mobilya', 'Owner', '0569350333', 'PS', 'Bethlehem', 'Bethlehem - Palestine', '10+ years', NULL, NULL, NULL, NULL, 1),
