(183, 'Azza Shaikh Ahmad', 'Owner', 'azzaa6177@gmail.com', 1, 'profiles/profile_183.jpg', NULL, 'covers/hero_183.jpg', 'visual artist from Gaza, known for her expressive paintings that explore identity, memory, heritage, and the Palestinian experience. With a background in art education and years of experience as an educator and artist, she has exhibited her work locally and internationally, including solo shows in Gaza and Berlin. Her art often reflects resilience, cultural memory, and the stories of her community, using both color and black-and-white palettes to convey depth and emotion.', NULL, 1, 1, 1, 1, NULL, 0, 0, 0, 0, 1, 0, 0, 11, 0, 0, NULL, '$2y$12$wPxwVCng7KFMPwsMxB6MouTZ.dmAbtN3IZBOFviDWv7ldUQb0NJn6', NULL, '2025-12-24 12:13:33', '2026-02-18 10:15:29', 'Azza', 'Shaikh Ahmad', 'designer', 'Graphic Designer', 'Azza Shaikh Ahmad', 'Owner', '599906696', 'PS', 'Gaza', 'Gaza - Palestine', '10+ years', NULL, NULL, NULL, NULL, 1),
