(198, 'شركة الميمي لعالم الاخشاب و لوازم النجارين', 'CEO - Owner', 'mohammad@mimi-pal.ps', 1, 'profiles/profile_198.jpg', NULL, 'covers/hero_198.jpg', 'is a well-established wood and carpentry supplies company based in Ramallah and Al-Bireh, Palestine. The business specializes in providing a wide range of high-quality wood products and accessories tailored to the needs of carpenters, builders, and woodworking professionals. The company offers essential materials such as timber, wood panels, and construction wood, along with tools and supplies used by carpenters. As a trusted local supplier, Al-Mimi serves individual and large projects', NULL, 1, 1, 1, 1, NULL, 0, 0, 0, 0, 1, 0, 0, 6, 0, 0, '2026-01-12 07:41:29', '$2y$12$XOzig8PvUOhuPPhiLqRit.QAoBIw7.QkJNCIrPY70u/AJa8s4wVy2', NULL, '2026-01-12 07:41:29', '2026-02-04 04:11:29', 'Mohammad', 'Mimi', 'supplier_vendors', 'Wood Supplier', 'شركة الميمي لعالم الاخشاب و لوازم النجارين', 'CEO - Owner', '568440004', 'PS', 'Ramallah and Al-Bireh', 'Al-Bireh Industrial Area, next to Al-Bireh Municipality Square or the Gas Filling Company, Ramallah, Palestine.', '10+ years', NULL, NULL, NULL, NULL, 1),
(199, 'منجرة الأصدقاء', 'مدير المصنع', 'jehad.khater200@gmail.com', 1, 'profiles/profile_199.jpg', NULL, 'covers/hero_199.jpeg', 'تقع منجرة الأصدقاء في جفنا، وتمتلك خبرة تزيد عن 15 عامًا في النجارة وصناعة الأثاث. تختص الورشة في تصنيع أثاث عالي الجودة حسب الطلب، حيث تمزج بين الحرفية التقليدية والتصميم العصري لإنتاج قطع متينة وأني', NULL, 1, 1, 1, 1, NULL, 0, 0, 0, 0, 1, 0, 0, 14, 0, 0, '2026-01-12 08:55:31', '$2y$12$M5C.xTNKpTOMDVGIm1YflOG4Yv1cuhZ5oneFsK9wVRo3vn0DlsAXK', NULL, '2026-01-12 08:55:31', '2026-02-18 09:15:27', 'Jehad', 'Khater', 'manufacturer', 'Furniture Manufacturer', 'منجرة الأصدقاء', 'مدير المصنع', '599282818', 'PS', 'Ramallah and Al-Bireh', 'رام الله - جفنا', '10+ years', NULL, NULL, NULL, NULL, 1),
(200, 'Click Light', 'CEO', 'Clickinght.2024@hotmail.com', 1, 'profiles/profile_200.jpg', NULL, 'covers/hero_200.jpg', 'شركة العمرانية الحديثة للإنارة والكهرباء هي شركة مقاولات وتجهيزات كهربائية مقرها في مدينة الخليل، فلسطين، متخصصة في توريد وتركيب أنظمة الإنارة والكهرباء للمنازل، المؤسسات، والشركات. تقدم الشركة حلولاً متكاملة في مجال الإنارة الحديثة، التركيبات الكهربائية، وصيانة الشبكات، مع الالتزام بالجودة ومعايير السلامة المهنية. تعتمد الشركة على خبرة متميزة في تنفيذ المشاريع الكهربائية والإنارة في مختلف المواقع السكنية والتجارية والصناعية، وتعمل على تلبية احتياجات الزبائن من تصميم حتى تنفيذ وتسليم المشروع بأع', NULL, 1, 1, 1, 1, NULL, 0, 0, 0, 0, 1, 0, 0, 32, 0, 0, '2026-01-12 10:02:45', '$2y$12$BCC4mzBqiQkoXB25yUC7NuGR6VPfhdXhSxLpLti/dBGB33qZ1eDQW', NULL, '2026-01-12 10:02:45', '2026-02-19 06:31:07', 'Click', 'Light', 'supplier_vendors', 'Lightning Supplier', 'الشركة العمرانية الحديثة للإنارة والكهرباء', 'CEO', '598122588', 'PS', 'Hebron', 'الحرس شارع أضواء المدينة', '10+ years', NULL, NULL, NULL, NULL, 1),
(201, 'Click Home', 'CEO', 'Islamabdeen132@hotmail.com', 1, 'profiles/profile_201.png', NULL, 'covers/hero_201.png', 'كليك هوم للمفروشات هي الذراع المتخصص في الأثاث والديكور لشركة كليك لايت، تقدم حلول مبتكرة وعصرية لتجهيز المنازل، المكاتب، والمحلات التجارية. تتميز الشركة بخبرة طويلة في تصميم وتصنيع الأثاث العصري، مع التركيز على الجودة العالية والتفاصيل الدقيقة لتلبية مختلف احتياجات العملاء. تشمل منتجاتها غرف نوم، غرف نوم أطفال، مطابخ، خزائن للتخزين، وأثاث عرض للمحلات.', NULL, 1, 1, 1, 1, NULL, 0, 0, 0, 0, 1, 0, 0, 9, 0, 0, '2026-01-12 10:24:10', '$2y$12$QDtZ7KW/PDbMbfCK74ZauOE.nRxSvLpPqEUx5ZHL1Kf80gNJZ6kWu', NULL, '2026-01-12 10:24:10', '2026-02-16 05:34:52', 'Click', 'Home', 'manufacturer', 'Furniture Manufacturer', 'Click home', 'CEO', '598122588', 'PS', 'Hebron', 'الخليل - الحرس - شارع أضواء المدينة', '10+ years', NULL, NULL, NULL, NULL, 1),
(202, 'Quzmar Machines', 'CEO', 'Mohammed@quzmar.ps', 1, 'profiles/profile_202.jpg', NULL, 'covers/hero_202.jpg', 'قزمار للماكينات شركة فلسطينية متخصصة في توريد وصيانة ماكينات النجارة والمعدات الصناعية، بالإضافة إلى توفير الأخشاب واللوازم الورشية. خبرة طويلة في دعم الحرفيين والصناعيين بأحدث الماكينات والخدمات الفنية.', NULL, 1, 1, 1, 1, NULL, 0, 0, 0, 0, 1, 0, 0, 23, 0, 0, '2026-01-13 08:59:19', '$2y$12$Wt9dWWE8F40G5Mb4/9KDS.acX3oQvy9Egii9amwrM9DUXOvU0le8a', NULL, '2026-01-13 08:59:19', '2026-02-15 23:43:46', 'Quzmar', 'Machines', 'supplier_vendors', 'Mechanical Supplier', 'Quzmar Machines قزمار للماكينات', 'CEO', '569466038', 'PS', 'Hebron', 'سنيريا - قلقيلية الفرع الاول \r\nبيتونيا - رام الله  الفرع الثاني', '10+ years', NULL, NULL, NULL, NULL, 1),
(203, 'Quzmar Company', 'CEO', 'info@Quzmar.ps', 1, 'profiles/profile_203.jpg', NULL, 'covers/hero_203.jpg', 'شركة قزمار للتجارة والصناعة هي شركة فلسطينية رائدة في توريد معدات النجارة، الأخشاب، واللوازم الصناعية للورش والمصانع. تأسست الشركة عام 1987، وتعمل على تلبية احتياجات النجارين والحرفيين عبر توفير ماكينات نجارة حديثة وجديدة ومستعملة، أنواع متعددة من الأخشاب، أدوات النجارة، ودهانات خاصة بالأخشاب. كما حصلت على وكالات لمنتجات عالمية في هذا المجال وتوفر خدمات النقل والتركيب والصيانة لعملائها داخل الضفة الغربية.', NULL, 1, 1, 1, 1, NULL, 0, 0, 0, 0, 1, 0, 0, 53, 0, 0, '2026-01-13 09:43:14', '$2y$12$BD19klQ02jZUxQN4q0ScdOnAmJIYJ32nP6dg.bPrZ9eJckX0.OGJ6', NULL, '2026-01-13 09:43:14', '2026-02-20 01:05:42', 'Quzmar', 'Company', 'supplier_vendors', 'Wood Supplier', 'شركة قزمار للتجارة والصناعة', 'CEO', '566700220', 'PS', 'Salfit', 'شارع مسحة - بديا - سلفيت', '10+ years', NULL, NULL, NULL, NULL, 1),
(205, 'Baitona Furniture', 'CEO - Ameed Hbeisheh', 'baitona.f@gmail.com', 1, 'profiles/profile_205.jpg', NULL, 'covers/hero_205.jpg', 'تُعد بيتنا للمفروشات من المعارض الرائدة في مجال الأثاث المنزلي في شارع بيت وزن – نابلس، حيث تقدم مجموعة متنوعة من المفروشات العصرية والكلاسيكية التي تجمع بين الجودة العالية والتصميم العملي. يحرص المعرض على تلبية احتياجات مختلف الأذواق من خلال توفير حلول متكاملة لتأثيث المنازل، مع التركيز على المتانة، الجمالية، والأسعار المناسبة.', NULL, 1, 1, 1, 1, NULL, 0, 0, 0, 0, 1, 0, 0, 13, 0, 0, '2026-01-18 07:20:56', '$2y$12$mK47Y3JxgalYjlN2u3oHDuXQh4xq4bkbJqjyMZa7jJyhT2QvvgFPe', NULL, '2026-01-18 07:20:56', '2026-02-06 09:03:00', 'Baitona', 'Furniture', 'manufacturer', 'Furniture Manufacturer', 'Baitona Furniture  بيتنا للمفروشات', 'CEO - Ameed Hbeisheh', '599095005', 'PS', 'Nablus', 'نابلس - شارع بيت وزن', '10+ years', NULL, NULL, 'https://www.facebook.com/BaitonaFurniture/photos?locale=ar_AR', NULL, 1),
(206, 'Venues furniture', 'CEO', 'venuesfurniture@gmail.com', 1, 'profiles/profile_206.jpg', NULL, 'covers/hero_206.jpg', 'مفروشات الأماكن متخصصة في تصميم وتوريد الأثاث العصري والعملي للمنازل والمساحات التجارية. ندمج بين التصميم الحديث وجودة التنفيذ لنقدم حلولاً متكاملة ترتقي بجمالية كل مكان.', NULL, 1, 1, 1, 1, NULL, 0, 0, 0, 0, 1, 0, 0, 13, 0, 0, '2026-01-19 11:25:45', '$2y$12$LU.fBRPDUTRl6xxlnTIoietuVWOIRt25QNWZQim2yiW/cHkxU5THi', 'yINKiP9xHa7jRIPyqp9GtRqboAnpPFyRaHlOO3FYmH12REsJenLt5Jfq3jsx', '2026-01-19 11:25:45', '2026-02-20 16:41:20', 'Venues', 'furniture', 'manufacturer', 'Furniture Manufacturer', 'Venues Furniture & design - مفروشات الأماكن', 'CEO', '569337733', 'PS', 'Nablus', 'نابلس - شارع بيت ايبا الرئيسي', '10+ years', NULL, NULL, NULL, NULL, 1),
(207, 'شركة ومصنع العشيبي للمفروشات', 'CEO', 'baha.eshibe@gmail.com', 1, 'profiles/profile_207.jpg', NULL, 'covers/hero_207.jpg', 'شركة العشيبي للمفروشات تقدم أثاثاً عالي الجودة بتصاميم أنيقة تُضفي الراحة والجمال على كل منزل. بشغف نحو التصميم واهتمام بأدق التفاصيل، نوفر حلول أثاث تناسب مختلف الأذواق والمساحات — من غرف المعيشة المريحة إلى غرف النوم العملية وغرف الطعام المميزة.', NULL, 1, 1, 1, 1, NULL, 0, 0, 0, 0, 1, 0, 0, 14, 0, 0, '2026-01-19 17:03:14', '$2y$12$S4lg4QN1XWj7AZM.jBYW8.M9iCYV9qHP6FXxuAVb1SJMfce8FHCRm', NULL, '2026-01-19 17:03:14', '2026-02-19 15:55:20', 'Bahaa', 'Aleshibe', 'manufacturer', 'Furniture Manufacturer', 'Aleshibe Furniture - العشيبي للمفروشات', 'CEO', '569005511', 'PS', 'Nablus', 'نابلس /شارع بيت ايبا الرئيسي', '5-10 years', NULL, NULL, NULL, NULL, 1),
(208, 'Global Furniture', 'CEO', 'globalfurnitre631@gmail.com', 1, 'profiles/profile_208.jpg', NULL, 'covers/hero_208.jpg', 'Global Furniture – نابلس تقدّم حلول أثاث عالية الجودة بتصاميم أنيقة تناسب المنازل والمكاتب على حد سواء. نركز على جودة التنفيذ والراحة والأناقة، ونوفر قطع أثاث تكمّل ديكور المكان وتضيف لمسة من الفخامة والوظيفة. مع خبرة واسعة وشغف بالتصميم، نلبي احتياجاتك من غرفة المعيشة حتى غرفة النوم والمكتب بأفضل قيمة.', NULL, 1, 1, 1, 1, NULL, 0, 0, 0, 0, 1, 0, 0, 3, 0, 0, '2026-01-19 17:53:10', '$2y$12$njM0w5IGWRvL48oT4o6qje9iauEEevxzExkp9ZSIpYFthGn9S9md6', NULL, '2026-01-19 17:53:10', '2026-02-18 05:49:48', 'Global', 'Furniture', 'manufacturer', 'Furniture Manufacturer', 'Global Furniture', 'CEO', '568115120', 'PS', 'Nablus', 'نابلس - بيت ايبا الصناعية', '10+ years', NULL, NULL, NULL, NULL, 1),
(209, 'Jehad Haj Mohammad', 'Designer', 'had10.1996@hotmail.com', 1, 'profiles/profile_209.png', NULL, 'covers/hero_209.png', 'A passionate Interior Designer dedicated to transforming spaces into functional, beautiful, and inspiring environments. Specializing in residential, commercial, and hospitality projects, I blend creativity with practicality to create designs that reflect personal style and enhance everyday living. Every detail matters, from color palettes to furniture selection, ensuring each space tells a unique story.', NULL, 1, 1, 1, 1, NULL, 0, 0, 0, 0, 1, 0, 0, 5, 0, 0, '2026-01-19 17:59:26', '$2y$12$X/7Wd80/L7ugENr4exQltesCa3zor7rNO2hbTqKFoaEs8ciYunjCi', NULL, '2026-01-19 17:59:26', '2026-02-10 08:22:20', 'Jehad', 'Haj Mohammad', 'designer', 'Interior Designer', 'Jehad Haj Mohammad', 'Designer', '568446694', 'PS', 'Nablus', 'Nablus - main street', '3-5 years', NULL, NULL, NULL, NULL, 1),
(210, 'Leo Accessories Home', 'CEO', 'Aboodhh2261@gmail.com', 1, 'profiles/profile_210.jpg', NULL, 'covers/hero_210.jpg', 'Leo Accessories Home تقدّم مجموعة منتقاة من ديكورات المنزل والإكسسوارات التي تضيف لمسة من الأناقة والشخصية لكل زاوية في المنزل. من القطع الزخرفية الأنيقة إلى حلول التخزين العملية، نهدف إلى تحويل المساحات إلى بيوت مليئة بالدفء والجمال بتصاميم تناسب كل ذوق.', NULL, 1, 1, 1, 1, NULL, 0, 0, 0, 0, 1, 0, 0, 11, 0, 0, '2026-01-19 18:12:28', '$2y$12$jn0TzBfvYGcINi.4axaZguuM//ORtrLUJkwmXg93U1CbArurhZ4AS', NULL, '2026-01-19 18:12:28', '2026-02-19 10:17:28', 'Leo Accessories', 'Home', 'showroom', 'Furniture Showroom', 'Leo Accessories Home', 'CEO', '598757594', 'PS', 'Nablus', 'شارع بيت ايبا الرئيسي', '3-5 years', NULL, NULL, 'https://www.facebook.com/p/Leo-Accessories-Home-100091175253063/', NULL, 1),
(211, 'Almasri Furniture', 'CEO', 'masri.for.furniture@gmail.com', 1, 'profiles/profile_211.jpg', NULL, 'covers/hero_211.jpg', 'مجمع المصري للمفروشات يقدم تشكيلة واسعة من الأثاث عالي الجودة وحلول المنزل المتكاملة التي تضفي جمالاً وراحة على كل مساحة. من أطقم غرف المعيشة الأنيقة وغرف النوم المريحة إلى المطابخ العملية وغرف الطعام الراقية، نمزج بين التصميم الأنيق والمتانة طويلة الأمد. نلتزم بتقديم منتجات متميزة وخدمة شخصية تلبي احتياجات وأذواق كل عميل.', NULL, 1, 1, 1, 1, NULL, 0, 0, 0, 0, 1, 0, 0, 4, 0, 0, '2026-01-19 18:16:12', '$2y$12$1WPaj11Nm0D/1WMzywNn/OGX0yaQlnFF1MXfIoHyhP0wwoMD3OUw2', NULL, '2026-01-19 18:16:12', '2026-02-11 14:15:24', 'Almasri', 'Furniture', 'manufacturer', 'Furniture Manufacturer', 'مجمع المصري للمفروشات', 'CEO', '598025424', 'PS', 'Nablus', 'فلسطين_ نابلس _ شارع رفيديا / شارع بيت ايبا / المصنع : دير شرف', '10+ years', NULL, NULL, 'https://www.facebook.com/masri.for.furniture', NULL, 1),
(213, 'Al Raed Furniture', 'CEO', 'furnitureraed@gmail.com', 1, 'profiles/profile_213.jpg', NULL, 'covers/hero_213.jpg', 'معرض مختص في الأثاث والمفروشات المنزلية يقع في أم الشرايط، رام الله والبيرة بأعلى جودة وأحدث التصاميم، مقابل كازية النبالي والخواجا.\r\nمنذ أكثر من 30 عاماً، يقدم الرائد للمفروشات تشكيلات واسعة ومتنوّعة من الأثاث المنزلي والمكتبي التي تجمع بين الجودة العالية، الأناقة، والراحة لتلبية أذواق جميع العملاء.\r\n🛋️ منتجاتنا تشمل:\r\n• صالونات وانترية بتصاميم مودرن وكلاسيك\r\n• غرف نوم بجميع القياسات\r\n• طاولات طعام\r\n• أثاث مكتبي\r\n• غرف أطفال ووحدات تخزين\r\nوخيارات متعددة من الخامات \r\n546303131رقم للتواصل', NULL, 1, 1, 1, 1, NULL, 0, 0, 0, 0, 1, 0, 0, 27, 0, 0, '2026-01-20 08:53:33', '$2y$12$3c6Efw5fSMZh3qEYDIAkGuH/Pa4WztObYWAGiJ844t8qi5M4glGAW', 'BQ5ouEHgNx88Zm0AkYyTR85TooF2SpjYqMgxd1xJejiNWZCezKSOruxeoloT', '2026-01-20 08:53:33', '2026-02-18 17:46:23', 'Al Raed', 'Furniture', 'manufacturer', 'Furniture Manufacturer', 'الرائد للمفروشات - Al Raed Furniture', 'CEO', '595444984', 'PS', 'Ramallah and Al-Bireh', 'رام الله - ام الشرايط - كازية الخواجا', '10+ years', NULL, NULL, NULL, NULL, 1),
(215, 'Taj Home', 'CEO', 'Ismael.designer2014@gmail.com', 1, 'profiles/profile_215.jpg', NULL, 'covers/hero_215.jpg', 'تاج هوم هو متجر وماركة للأثاث والديكور المنزلي والمنتجات المنزلية العصرية، يقدّم مجموعة واسعة من السلع لتجهيز وتأثيث المنزل بأسلوب جميل وفريد. تشمل منتجاتهم غالبًا أثاث، إكسسوارات منزلية، ديكور، وربّما منتجات أخرى ذات طابع منزلي مميز يتم عرضها وبيعها عبر موقعهم الإلكتروني ومنصات التواصل الاجتماعي', NULL, 1, 1, 1, 1, NULL, 0, 0, 0, 0, 1, 0, 0, 31, 0, 0, '2026-01-21 10:00:46', '$2y$12$2JOg5kJRF1OTBEJbDnq0gOHSM4oTeLT/2SSpXEiclkeQchyoq8iAW', NULL, '2026-01-21 10:00:47', '2026-02-19 16:37:12', 'Taj', 'Home', 'manufacturer', 'Furniture Manufacturer', 'تاج هوم - Taj Home', 'CEO', '599307679', 'PS', 'Ramallah and Al-Bireh', 'جنين - الزبابدة - الشارع الرئيسي\r\nرام الله - شارع رافات - بالقرب من عرابي - مدخل رفات البلد', '3-5 years', NULL, NULL, NULL, NULL, 1),
(216, 'NEVADA FURNITURE', 'CEO', 'Ralraed38@gmail.com', 1, 'profiles/profile_216.jpg', NULL, 'covers/hero_216.jpg', 'مفروشات نيفادا هو وجهتك المثالية لأثاث منزلي أنيق وعالي الجودة يجمع بين الراحة والتصميم الراقي لتجميل كل زاوية في بيتك. \r\n\r\nنقدّم تشكيلة واسعة من قطع الأثاث المتنوعة مثل:\r\nأطقم كنب حديثة وعملية\r\nطاولات وسط وطاولات طعام بتصاميم راقية\r\nغرف نوم كاملة متناسقة\r\nكراسي فردية وقطع مميزة تضفي شخصية على الفراغ\r\nقطع ديكور تضفي لمسة جمالية للمكان', NULL, 1, 1, 1, 1, NULL, 0, 0, 0, 0, 1, 0, 0, 5, 0, 0, '2026-01-21 10:50:03', '$2y$12$xS5mGmOmbCI6zkR/Xn0FAucUk9QHvVsS5N7bMm8gurhmncfwh.8zq', NULL, '2026-01-21 10:50:04', '2026-02-05 08:03:09', 'NEVADA', 'FURNITURE', 'showroom', 'Furniture Showroom', 'مفروشات نيفادا-NEVADA FURNITURE', 'CEO', '586303131', 'PS', 'Ramallah and Al-Bireh', 'ام الشرايط-الشارع الرئيسي-مفرق بلوط-قرب مركز دار الشفاء الطبي', '10+ years', NULL, NULL, NULL, NULL, 1),
(217, 'ROYAL FURNITURE', 'CEO', 'abusalha.ramallah@gmail.com', 1, 'profiles/profile_217.jpg', NULL, 'covers/hero_217.jpg', 'مفروشات رويال هو معرض أثاث منزلي متكامل يقدم قطع أثاث عالية الجودة وتصاميم متنوعة تناسب كل أذواق المنازل والمساحات، من غرف نوم وأطقم كنب وطاولات سفرة إلى مكاتب وكراسي وقطع ديكور مميزة، مع خيارات تفصيل حسب الطلب بالألوان والتصاميم اللي بتناسب ذوقك.', NULL, 1, 1, 1, 1, NULL, 0, 0, 0, 0, 1, 0, 0, 6, 0, 0, '2026-01-21 11:02:50', '$2y$12$c2/D8uaQfFmA/3u5.dKal.9AHRmEvqDEhJmh1wIuVvKNK7kYMCS1q', NULL, '2026-01-21 11:02:50', '2026-02-05 10:17:45', 'ROYAL', 'FURNITURE', 'manufacturer', 'Furniture Manufacturer', 'ROYAL FURNITURE', 'CEO', '599385826', 'PS', 'Ramallah and Al-Bireh', 'شارع الإرسال - عمارة الإسراء - التسوية الرابعة', '10+ years', NULL, NULL, NULL, NULL, 1),
(218, 'Abu Salha Furniture', 'CEO', 'abusalahnablus@gmail.com', 1, 'profiles/profile_218.jpg', NULL, 'covers/hero_218.jpg', 'وجهتك الأولى لحلول الأثاث المتكاملة! نقدم لك خدمات تصميم واستشارات احترافية لتنسيق المساحات، أثاث مخصص حسب الطلب، وتوصيل وتركيب سريع في المنزل أو المكتب.\r\nنرافقك من أول فكرة حتى الإكمال، مع متابعة ما بعد البيع لضمان راحتك ورضاك.\r\nتصميم ذكي — تنفيذ ممتاز — خدمة لا مثيل لها.', NULL, 1, 1, 1, 1, NULL, 0, 0, 0, 0, 1, 0, 0, 7, 0, 0, '2026-01-21 12:18:52', '$2y$12$Q1O7aLl7EuJ/ItiNauYamuC.6.JDlBXkG2YIa3xc2KrwqqkY34h7u', NULL, '2026-01-21 12:18:52', '2026-02-05 10:17:48', 'Abu Salha', 'Furniture', 'manufacturer', 'Furniture Manufacturer', 'مجمع مفروشات أبو صالحة', 'CEO', '598228302', 'PS', 'Nablus', 'نابلس - شارع القدس - المنطقة الصناعية', '5-10 years', NULL, NULL, NULL, NULL, 1),
(219, 'Shahd Trading company', 'CEO', 'shahdramallah@gmail.com', 1, 'profiles/profile_219.jpg', NULL, 'covers/hero_219.png', 'وجهتك الموثوقة لكل احتياجات الأثاث والمنتجات المنزلية والمكتبية.\r\nنقدّم خدمات مميزة تشمل: تصميم أثاث حسب الطلب، استشارات ديكور، التوصيل والتركيب، وخدمات ما بعد البيع لضمان راحتك ورضاك الكامل.\r\n جودة، تنوع، وخدمة عملاء استثنائية', NULL, 1, 1, 1, 1, NULL, 0, 0, 0, 1, 1, 0, 0, 12, 0, 0, '2026-01-21 12:29:54', '$2y$12$WgbOh82FjL9B..VhnHjACeVgdEJfMwu8VVVPf7HNICfsjxcik8p4G', NULL, '2026-01-21 12:29:54', '2026-02-16 13:35:54', 'Shahd Trading', 'company', 'manufacturer', 'Furniture Manufacturer', 'Shahd Trading Co. مؤسسة شهد التجارية', 'CEO', '593399447', 'PS', 'Ramallah and Al-Bireh', 'فروع مؤسسة شهد التجارية: مدينة بيت لحم / مدينة رام الله / مدينة نابلس / مدينة طولكرم', '10+ years', NULL, NULL, NULL, NULL, 1),
