(223, 'Vendor User', 'CEO', 'vendor@gmail.com', 1, 'profiles/profile_223.jpg', NULL, 'covers/hero_223.jpg', 'is a trusted provider of high-quality electrical components and solutions, specializing in serving architects, showrooms, and furniture manufacturers. With a focus on reliability, innovation, and design-friendly solutions, we help professionals bring their creative projects to life while ensuring safety, efficiency, and compliance with industry standards.', NULL, 1, 1, 1, 1, NULL, 0, 0, 0, 0, 1, 0, 0, 11, 0, 0, '2026-01-22 10:24:30', '$2y$12$ZZRNX7DCiYtr.iVzOSdCBeLcaCZ/jZEBGRWrafTZlSAw2oW1daMyu', NULL, '2026-01-22 10:24:30', '2026-02-06 07:50:31', 'Vendor', 'User', 'supplier_vendors', 'Electrical supplier', 'Electrical Supplier', 'CEO', '597666887', 'PS', 'Nablus', 'Palestine - Nablus', '10+ years', NULL, NULL, NULL, NULL, 1),
