(228, 'The Room Decor', 'CEO', 'Rahmazaghari2@gmail.com', 1, 'profiles/profile_228.jpg', NULL, 'covers/hero_228.jpg', 'شركة The Room Decor هي شركة أثاث وديكور فلسطينية مقرّها في أريحا، شارع عمان مقابل مطعم باركودا، تقدّم قطع أثاث عالية الجودة تجمع بين الراحة والتصميم العصري المصنوع محليًا في فلسطين. تُعرف الشركة بابتكاراتها في الأثاث التي تركز على الراحة والمتانة مع لمسات تصميم مميزة تُناسب المنازل والمساحات الداخلية، وتعرض أعمالها ومشاريعها المختلفة عبر منصاتها على التواصل الاجتماعي بما يشمل تصميم غرف الأطفال والقطع المخصصة حسب الطلب.', NULL, 1, 1, 1, 1, NULL, 0, 0, 0, 0, 1, 0, 0, 11, 0, 0, '2026-01-31 08:35:14', '$2y$12$ksVBz7PUk4u676FU/x15f.9HEAerkWoC9r.LG3M0M2uxyHj5apwcy', NULL, '2026-01-31 08:35:14', '2026-02-16 01:09:42', 'The Room', 'Decor', 'manufacturer', 'Furniture Manufacturer', 'للأثاث The room decor شركة', 'CEO', '598000055', 'PS', 'Jericho', 'شارع عمارن - اريحا - فلسطين', '1-3 years', NULL, NULL, NULL, NULL, 1),
(229, 'Medas Furniture', 'CEO', 'Amjadmedas@gmail.com', 0, 'profiles/profile_229.jpg', NULL, 'covers/hero_229.jpg', 'منذ تأسيسها عام 2005، رسّخت شركة ميداس للمفروشات مكانتها كواحدة من الشركات الرائدة في عالم المفروشات، من خلال الجمع بين التصميم العصري، الجودة العالية، والدقة في التصنيع.\r\nتمتلك ميداس فرعين رئيسيين في الخليل وأريحا، إلى جانب مقر تصنيع احترافي متكامل يعتمد على أحدث التقنيات ويعمل بأيدٍ خبيرة، ما يضمن تقديم منتجات تلبي أعلى المعايير وتواكب تطلعات العملاء.', NULL, 1, 1, 1, 1, NULL, 0, 0, 0, 0, 1, 0, 0, 11, 0, 0, '2026-01-31 09:00:07', '$2y$12$LyFwEvPw9RxEkyECbrSypO00lrYwH8xxByrxh3xsT5W/E9FYBS912', 'nKpCIrQxNLQ4TxLCs0aCgwKbZHGvoJuwfdCNtK9OvQHhO0A2eMKtAZEpsAEh', '2026-01-31 09:00:07', '2026-02-14 17:54:33', 'Medas', 'Furniture', 'manufacturer', 'Furniture Manufacturer', 'ميداس للمفروشات', 'CEO', '599205825', 'PS', 'Hebron', 'المصنيع - الخليل\r\nالمعرض - اريحا والخليل', '10+ years', NULL, NULL, NULL, NULL, 0),
(230, 'Salsabeel Elayyan', 'Freelance designer', 'elayyansalsabeel@gmail.com', 0, 'profiles/profile_230.jpeg', NULL, 'covers/hero_230.jpeg', 'Im interested in learning new techniques and using AI in designs', NULL, 1, 1, 1, 1, NULL, 0, 0, 0, 0, 1, 0, 0, 3, 0, 0, '2026-02-01 04:55:50', '$2y$12$pQzX2yl0DUCWU5XLtEjrB.DJerVbdeBgeh04XvizlWRqh.LWvulry', NULL, '2026-02-01 04:55:50', '2026-02-19 02:23:33', 'Salsabeel', 'Elayyan', 'architect', 'Engineering', 'Salsabeel Elayyan Architect', 'Freelance designer', '569957199', 'IL', 'Hebron', 'Hebron-Dura', '3-5 years', NULL, NULL, NULL, NULL, 0);
