(231, 'Yara Barghouthy', 'Partnerships and Project Coordinator', 'yara.barghouthy2002@gmail.com', 0, 'profiles/profile_231.jpeg', NULL, 'covers/hero_231.jpeg', 'Yara Barghouthy is an architectural engineer and Research & Teaching Assistant at Birzeit University. Her work bridges design, research, and visualization, with interests in spatial justice, everyday life, and ecology. She supports studios in model-making and digital fabrication and works as a freelance architectural visualizer, producing drawings and renders that translate complex ideas into clear, compelling spatial narratives.', NULL, 1, 1, 1, 1, NULL, 0, 0, 0, 0, 1, 0, 0, 2, 0, 0, '2026-02-02 05:03:13', '$2y$12$AVA7L.Q18cEtssIf9Mb3m.j1bvmqEyBpDTPyqucxlO8exg82TgunG', 'zDukK4QzcA6aPagNHdGVV62Kjv1m8dEFyDMPWb8OibJqQZwmHR2DtQBoPSmD', '2026-02-02 05:03:13', '2026-02-06 08:55:46', 'Yara', 'Barghouthy', 'architect', 'Restoration Architect', 'Taawon (Welfare Association)', 'Partnerships and Project Coordinator', '597396713', 'PS', 'Ramallah and Al-Bireh', 'Albireh\r\nEm Al Sharayet', '0-1 years', NULL, NULL, NULL, NULL, 0),
(232, 'Dubai Furniture', 'CEO', 'df111210@yahoo.com', 0, 'profiles/profile_232.jpg', NULL, 'covers/hero_232.jpg', 'دبي للأثاث متجر متخصص في بيع الأثاث المنزلي والمكتبي والأجهزة الكهربائية والإلكترونية. يضم منتجات محلية متنوعة ويخدم السوق الفلسطيني منذ حوالي 15 عاماً. لديهم فريق عمل متكامل لمساعدة العملاء في اختيار التصاميم المناسبة، ويقع المتجر في رام الله – شارع الإرسال.', NULL, 1, 1, 1, 1, NULL, 0, 0, 0, 0, 1, 0, 0, 31, 0, 0, '2026-02-02 08:18:35', '$2y$12$ClHDdk1LiaITQmWZaFkL5ehSLKgtm/8YJed5EjJ73s8hHh4AP6UMa', 'KVPNyyV98GyARjEZ8VMFRwjzyqcAnRQZ2DTTajVBxpGQ1IPJo6msb3rHOPVb', '2026-02-02 08:18:35', '2026-02-20 12:37:29', 'Dubai', 'Furniture', 'showroom', 'Furniture Showroom', 'Dubai Furniture', 'CEO', '592182553', 'PS', 'Ramallah and Al-Bireh', 'رام الله-البيرة-شارع الارسال-مقابل شركة الكهرباء', '10+ years', NULL, NULL, 'https://www.facebook.com/DubaiFurniture?locale=ar_AR', NULL, 0),
(234, 'High fashion furniture', 'CEO', 'naielhamdan@gmail.com', 0, 'profiles/profile_234.jpg', NULL, 'covers/hero_234.jpg', 'هي شركة متخصصة في بيع الأثاث المنزلي والمكتبي وحدائق في رام الله والبيرة، وتقدم تشكيلة متنوعة من المفروشات لتلبية احتياجات البيوت والمكاتب. يقع المعرض في البالوع بجانب شركة القدس للمستحضرات الطبية، ويشتهر بتقديم أثاث بتصاميم متعددة وجودة مناسبة للسوق المحلي', NULL, 1, 1, 1, 1, NULL, 0, 0, 0, 0, 1, 0, 0, 7, 0, 0, '2026-02-02 09:00:47', '$2y$12$DEWJ0Ji9JnB48aUKVn0GOOzye2y9AvM9dSGg0hOPA.H/YdJET1KLy', NULL, '2026-02-02 09:00:47', '2026-02-07 16:58:57', 'High', 'fashion furniture', 'manufacturer', 'Furniture Manufacturer', 'High Fashion Furniture هاي فاشن للاثاث', 'CEO', '599332329', 'PS', 'Ramallah and Al-Bireh', 'البيرة - البالوع - رام الله', '10+ years', NULL, NULL, NULL, NULL, 0),
(235, 'Saray Furniture', 'CEO', 'Masalmamarwan@gmail.com', 0, 'profiles/profile_235.jpg', NULL, 'covers/hero_235.jpg', 'سراي للمفروشات هو معرض أثاث يقدم مجموعة واسعة من الأثاث المنزلي والمكتبي بتصاميم متنوعة تجمع بين الأناقة والراحة. تعرف العلامة التجارية بأثاثها ذات التصميم العصري وجودة المواد المختارة بعناية لتلبية احتياجات الأسر والمكاتب. تتميز منتجات سراي بتركيزها على الوظائف الجمالية والمتانة، وتشمل مجموعات الأرائك، وطاولات المعيشة، وغرف النوم، ووحدات التخزين وغيرها', NULL, 1, 1, 1, 1, NULL, 0, 0, 0, 0, 1, 0, 0, 10, 0, 0, '2026-02-02 09:31:29', '$2y$12$TeEmYifpD./dc4PDs37c2u7PNGPFiANhUWwCta4oLGruqM1.qKjBu', NULL, '2026-02-02 09:31:29', '2026-02-10 19:03:18', 'Saray', 'Furniture', 'manufacturer', 'Furniture Manufacturer', 'Saray Furniture سراي للمفروشات', 'CEO', '568687403', 'PS', 'Jerusalem', 'العيزرية  - الشارع الرئيسي - بالقرب من البلدية', '10+ years', NULL, NULL, NULL, NULL, 0),
(236, 'Sven Rudolph', 'Head of Design', 'sven@rsw.design', 0, 'profiles/profile_236.jpg', NULL, 'covers/hero_236.jpg', 'RSW is an award-winning product design and innovation consultancy based in the heart of Germany. We combine research, strategy, design and *magic to create substantial innovations for our clients from start-ups to global players.', NULL, 1, 1, 1, 1, NULL, 0, 0, 0, 0, 1, 0, 0, 7, 0, 0, '2026-02-02 09:46:38', '$2y$12$WGg4akk8yKQicyB1BNg7JuUrSK88afZT/QaUkKPLT0cqMMN/hDPOu', 'XK7quQBfbO7wfmpF128PUacGyUL6BBFaKpMiTu7cKSHbvrY7EiPpKwblPsGC', '2026-02-02 09:46:38', '2026-02-18 09:28:16', 'Sven', 'Rudolph', 'designer', 'Product Designer', 'Rudolph Schelling Webermann GbR', 'Head of Design', '5113539376', 'DE', 'Ramallah and Al-Bireh', 'Ratswiese 18', '10+ years', NULL, NULL, NULL, NULL, 0),
(237, 'ALamal furniture', 'oner', 'muradezat@yahoo.com', 0, 'profiles/profile_237.jpg', NULL, 'covers/hero_237.jpg', 'مفروشات الأمل في العيزرية تُعد من أبرز المحلات المتخصصة في تصنيع وبيع الأثاث، حيث تجمع بين الخبرة والجودة لتلبية احتياجات المنازل والمكاتب والحدائق. يقدم المعرض خدمات متنوعة تشمل تصميم غرف الجلوس وغرف النوم حسب الطلب، إضافة إلى أعمال التنجيد وتجديد الأثاث القديم وصناعة الستائر. ما يميز مفروشات الأمل هو القدرة على تنفيذ الأثاث وفق رغبة الزبون باستخدام خامات عالية الجودة، مما يضمن الجمع بين المتانة والأناقة. بفضل موقعه في دوار الإسكان بالعيزرية وإدارته المحترفة، أصبح المعرض وجهة رئيسية للباحثين عن', NULL, 1, 1, 1, 1, NULL, 0, 0, 0, 0, 1, 0, 0, 4, 0, 0, '2026-02-02 09:55:11', '$2y$12$ADphTmVEe0zBl/dxjDCHLeMXIjD0eMtPwtbdSPkYG4wZieMGYSRp.', NULL, '2026-02-02 09:55:11', '2026-02-04 06:37:18', 'ALamal', 'furniture', 'manufacturer', 'Furniture Manufacturer', 'مفروشات الامل', 'oner', '0599210351', 'IL', 'Jerusalem', 'فلسطين - العيزريه - الكرد مول', '10+ years', NULL, NULL, NULL, NULL, 0),
(238, 'Almadina Furniture', 'CEO', 'Faresojra.84@gmail.com', 0, 'profiles/profile_238.jpg', NULL, 'covers/hero_238.jpg', 'معرض أثاث ومفروشات يقع في بلدة العيزرية، شرق القدس. يقدم المعرض مجموعة متنوعة من المفروشات، بما في ذلك غرف النوم، وغرف الأطفال، وأطقم الكنب، وأطقم التلفزيون، وغيرها من قطع الأثاث، مع التركيز على الجودة والتصميم العصري. يتميز بتوفير منتجات محلية ومستوردة لتلبية مختلف الأذواق والاحتياجات', NULL, 1, 1, 1, 1, NULL, 0, 0, 0, 0, 1, 0, 0, 14, 0, 0, '2026-02-02 10:13:45', '$2y$12$oAlzrG81qJltHqWvjMe1eu5vX/BQk.Pw7b8wWfMMgpANoVPOPg76m', NULL, '2026-02-02 10:13:45', '2026-02-19 18:35:26', 'Almadina', 'Furniture', 'manufacturer', 'Furniture Manufacturer', 'Almadian Furniture', 'CEO', '522898299', 'PS', 'Jerusalem', 'العيزرية - دوار وادي النار', '10+ years', NULL, NULL, NULL, NULL, 0),
(239, 'Mohammad Abu Sultan Furniture', 'Furniture Designer', 'Owainahmoh@gmail.com', 0, 'profiles/profile_239.jpg', NULL, 'covers/hero_239.jpg', 'مفروشات محمد أبو سلطان وأولاده للاثاث تُعد من أبرز الوجهات في مجال تصنيع وتجارة الأثاث، حيث تجمع بين الخبرة العائلية الطويلة والابتكار العصري لتقديم منتجات عالية الجودة تناسب مختلف الأذواق والمساحات. يختص المعرض بتصميم وتنفيذ غرف النوم، الصالونات، طاولات الطعام والسفرة، إضافة إلى الكنبايات والمفروشات المتنوعة، مع إمكانية التفصيل حسب رغبة الزبون لضمان الراحة والجمال في آن واحد. بفضل التزامه باستخدام خامات متينة واهتمامه بأدق التفاصيل، أصبح اسم \"محمد أبو سلطان وأولاده\" علامة ثقة وتميّز في عالم الأ', NULL, 1, 1, 1, 1, NULL, 0, 0, 0, 0, 1, 0, 0, 16, 0, 0, '2026-02-02 10:38:32', '$2y$12$NKnAcmHSEg9p0ChLUnnMl.udnjGot9CgMtxuXvIbpuSNlG8hcvuBi', NULL, '2026-02-02 10:38:32', '2026-02-17 12:51:19', 'Mohammad Abu Sultan', 'Furniture', 'designer', 'UX/UI Designer', 'مفروشات محمد ابو سلطان واولادة', 'Furniture Designer', '599948797', 'IL', 'Bethlehem', 'بيت لحم - شارع جمال عبد الناصر.', '10+ years', NULL, NULL, NULL, NULL, 0),
(241, 'Mahmoud AbuAmireh', NULL, 'mdaqqah@yahoo.com', 0, NULL, NULL, NULL, NULL, NULL, 1, 1, 1, 1, NULL, 0, 0, 0, 0, 1, 0, 0, 9, 0, 0, '2026-02-03 05:30:00', '$2y$12$6no6vOcL.6pYqunnVqBaQ.iw68RNaPMoUoPDfIv/EQIryprsPajFi', 'dJgL0qdhFSsDGomxYKjPl8SmgnY5Fza6pze2byOVUOufoSCLhja52L4YIjdb', '2026-02-03 05:30:00', '2026-02-18 15:16:50', 'Mahmoud', 'AbuAmireh', 'guest', 'Guest', NULL, NULL, NULL, 'PS', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 0),
(243, 'sana kayed', 'Graphic & Visual Content Designer', 'sanakayed2022@gmail.com', 0, 'profiles/011d8a9a-f603-4eff-8367-33ee1e5658c1.jpg', NULL, 'covers/hero_243.png', 'Visual content designer creating social media posts and brand identities for small businesses. Skilled in AI-assisted design to explore colors, layouts, and visual concepts efficiently.\r\n Focused on clear, consistent, and professional visuals.', NULL, 1, 1, 1, 1, NULL, 0, 0, 0, 0, 1, 0, 0, 14, 0, 0, '2026-02-03 09:57:01', '$2y$12$qXm2FcQy7SWbsD8NHl5cJOwglY92wnSLYon6rLBQ4ifZK.zJpFo7.', NULL, '2026-02-03 09:57:01', '2026-02-17 10:18:43', 'sana', 'kayed', 'designer', 'Graphic Designer', 'SK Visuals', 'Graphic & Visual Content Designer', '595488330', 'PS', 'Ramallah and Al-Bireh', 'Al-Birehhh', '1-3 years', NULL, NULL, NULL, NULL, 0),
