INSERT INTO `fab_labs` (`id`, `name`, `location`, `city`, `description`, `short_description`, `image`, `cover_image`, `rating`, `reviews_count`, `members`, `equipment`, `services`, `features`, `opening_hours`, `type`, `verified`, `phone`, `email`, `website`, `created_at`, `updated_at`) VALUES
(6, 'AL-Najah National University', 'Nablus - AL Najah National University', 'Nablus', 'AL-Najah National University – Located in Nablus, West Bank, with programs available at both the new campus and Hisham Hijjawi College,.\r\nThe university offers undergraduate and graduate programs in Energy Engineering, Clean Energy, and Mechanical Engineering, providing a comprehensive education in modern engineering fields.\r\n\r\nCollege of Engineering – ANU – Part of An-Najah National University, based in Nablus, WB. The college includes departments in Mechanical, Electrical, and Energy Engineering, focusing on preparing skilled engineers for regional and global industries.\r\n\r\nHisham Hijjawi College of Technology – Situated in Nablus, WB, this college specializes in Technology and Engineering education, offering practical and applied programs to equip students with hands-on skills for technical careers.', 'AL-Najah National University', 'fablabs/QEc4gul7QMF8M9COjcesx6aSja7c6IjmzigC4UYi.jpg', 'fablabs/covers/EvM64cfXMMOcN1tKpZJIRlD2vkBsi3BGnxtFS4qJ.jpg', 0.00, 0, 0, '[\"Advanced network routers & switches for training students in networking\",\"Industrial automation equipment (industrial controllers\",\"sensors\",\"actuators) as part of Applied Tech programs\",\"Auto mechanics and automotive technology tools for vehicle systems training\",\"Renewable energy & electrical engineering tools\",\"machine tools for manufacturing\\/production tech\"]', '[\"3D Printers\",\"Circuit production tools\",\"3D Scanners\",\"Laser Cutter\",\"CNC Machine\",\"mechanical\\/automation labs\"]', '[\"The Fab Labs at An-Najah National University and Hisham Hijjawi College of Technology provide students\",\"entrepreneurs\",\"and innovators with access to advanced digital fabrication tools such as 3D printers\",\"3D scanners\",\"laser cutters\",\"and CNC machines\",\"enabling rapid prototyping and product development. These labs support end-to-end workflows\",\"from CAD design to physical creation\",\"working with materials like plastics\",\"wood\",\"and metals. They also offer hands-on training\",\"workshops\",\"and collaborative spaces that encourage interdisciplinary projects\",\"innovation\",\"and problem-solving\",\"helping startups and students turn ideas into functional prototypes while fostering creativity\",\"skill-building\",\"and community engagement.\"]', 'Sunday – Thursday: 08:00 – 15:30 (official hours reported for the university administration)', 'fablab', 1, '+970 9 234 5113', 'info@najah.edu', 'www.najah.edu', '2026-01-13 12:07:13', '2026-01-14 11:12:42'),
(7, 'Birzeit University', 'Birzeit - Birzeit University', 'Birzeit - Ramallah', 'Birzeit University offers Mechanical Engineering, Mechatronics, and Renewable Energy programs within its Faculty of Engineering and Technology, including coursework and research focusing on solar and clean energy.', NULL, 'fablabs/vW99ZRss01PDOv1wZLkjbFzJOlEP9Gxr5Fd2dRxU.jpg', 'fablabs/covers/01UEw0d33yDS1HxaIuT5dQ6yXpXqCPt5c8TP6tnB.jpg', 0.00, 0, 0, '[\"Solar energy systems & demonstration plants\",\"Academic labs in engineering departments likely include experimental rigs such as solar energy minilab setups\",\"exhaust analyzers\",\"instrumentation for mechanical and renewable energy testing (common in such curricula\",\"though specific inventory listings aren\\u2019t publicly published)\"]', '[\"Technical guidance and supervision for lab work\",\"Support for research projects\",\"experiments\",\"and prototyping\",\"Access to specialized equipment like solar energy mini-labs and exhaust analyzers\",\"Hands-on training for students in Mechanical Engineering\",\"Mechatronics\",\"and Renewable Energy\"]', '[\"3D printing stations for rapid prototyping\",\"Renewable energy setups\",\"including solar panels and measurement tools\",\"Mechanical and mechatronic workstations for practical engineering exercises\",\"Safe and well-equipped engineering lab environment for experiments and testing\"]', 'Weekdays (Sun–Thu): ~08:00–16:00 (general university hours)', 'fablab', 1, '+970 2 298 2006', 'pr@birzeit.edu', 'www.birzeit.edu', '2026-01-13 12:21:31', '2026-01-14 11:15:28'),
(8, 'Palestine Polytechnic University Labs', 'Hebron -Polytechnic University', 'Hebron', 'The labs at Palestine Polytechnic University provide practical training and research facilities in Renewable Energy and the Water-Energy Nexus. They feature specialized workstations for water quality testing, renewable energy experiments, and environmental research, supporting students and faculty in hands-on learning, project work, and advanced experimentation.', 'Hands-on labs for renewable energy and water-energy nexus research', 'fablabs/7iWhe0qFFrgC9Ticsg3zt3dJv1nmfAbw9GAEaLic.jpg', 'fablabs/covers/WnPbOfCMkgp8f8xo4vFAbDhahQ0DFb50xGMzkG1G.jpg', 0.00, 0, 0, '[\"Solar panels\",\"Wind turbine models\",\"Water quality analyzers\",\"Sensors\",\"Energy meters\",\"Data loggers\"]', '[\"Hands-on experiments\",\"Research support\",\"Water quality testing\",\"Renewable energy prototyping\",\"Lab training\"]', '[\"WiFi\",\"Safety equipment\",\"Specialized workstations\",\"Laboratory benches\",\"Environmental research setups\"]', 'Monday to Friday  08:00 – 17:00  (official hours reported for the university administration)', 'fablab', 1, '+970-2-222-0000', 'info@ppu.edu', 'www.ppu.edu', '2026-01-13 12:27:20', '2026-01-14 11:11:33'),
(9, 'Palestine Technical University – Khadoorie PTUK', 'Tulkarm - Palestine Technical University', 'Tulkarm', 'TUK provides specialized labs and training systems for sustainable energy and engineering students, including photovoltaic (PV) and wind energy experimental setups. The campus emphasizes hands-on learning, research, and practical engineering skills.', 'University offering sustainable energy and engineering programs', 'fablabs/XruTv1cSaSoqfS1iMf5nfX8Q5EcHo42UNTJ0tiTU.jpg', 'fablabs/covers/w8UMFJG0lResJk4LhpDFVP2A2ZmIOhEh7WOqLi6h.jpg', 0.00, 0, 0, '[\"PV training systems\",\"wind energy systems\",\"electrical lab equipment\"]', '[\"Energy experiments\",\"engineering labs\",\"student training\",\"workshops\"]', '[\"WiFi\",\"Labs\",\"Safety equipment\",\"Hands-on training stations\"]', 'Monday to Friday 08:00 – 17:00 (official hours reported for the university administration)', 'fablab', 1, '+970-9-234-0000', 'info@ptuk.edu.ps', 'www.ptuk.edu.ps', '2026-01-13 12:35:40', '2026-01-14 11:11:09'),
(10, 'Al-Quds University – Engineering Labs', 'Abu Dis - Al-Quds University', 'Abu Dis', 'Equipped workshops for mechanical, electrical, and renewable energy engineering, including CNC machines, welding stations, and prototyping facilities for student projects and research', 'University labs for engineering and renewable energy studies.', 'fablabs/Wmvb67kT8SYI1opqG5V3hBCqLZ6FHlqvN7FEeSO7.jpg', 'fablabs/covers/eBwkL6ZlXfBrENMKtqlafDGKkGVgYaP2K1baCTUI.jpg', 0.00, 0, 0, '[\"CNC machines\",\"welding stations\",\"prototyping tools\",\"lab instruments\"]', '[\"Lab access\",\"prototyping\",\"welding and machining workshops\",\"engineering training\"]', '[\"WiFi\",\"Safety equipment\",\"Workshop space\",\"Hands-on training\"]', 'Monday to Friday 08:00 – 17:00 (official hours reported for the university administration)', 'fablab', 1, '+970-2-234-0000', 'pr@alquds.edu', 'www.alquds.edu', '2026-01-13 12:37:42', '2026-01-14 11:10:04'),
(11, 'Creative Hub – Palestine Techno park', 'Birzeit - Palestine Techno park', 'Birzeit - Ramallah', 'Provides 3D printing, scanning, and prototyping tools for startups and innovators.\r\nExpertise  staff  is required to operate some of the equipment', 'Creative Hub for tech innovation and prototyping', 'fablabs/SRDqurXykwiB4YuAbFutpTwHMFgkA42dT65ic6zp.jpg', 'fablabs/covers/BKQ8wJxenFi41rPvNKPw6a32VTG0D9nkM7tgHEXd.jpg', 0.00, 0, 0, '[\"3D printers\",\"scanners\",\"prototyping tools\"]', '[\"Prototyping\",\"innovation support\",\"tech experimentation\",\"startup support\"]', '[\"WiFi\",\"Collaboration spaces\",\"Training support\",\"Specialized equipment\"]', 'Monday to Friday 08:00 – 18:00', 'fablab', 1, '0593440216', 'info@technopark.ps', 'www.technopark.ps', '2026-01-14 10:25:04', '2026-01-14 11:10:50');
