INSERT INTO `marketplace_posts` (`id`, `designer_id`, `title`, `description`, `category`, `image`, `type`, `tags`, `likes_count`, `comments_count`, `views_count`, `bookmarks_count`, `approval_status`, `rejection_reason`, `approved_at`, `approved_by`, `created_at`, `updated_at`) VALUES
(13, 223, 'Switches & Sockets', 'Designer Wall Switches – Sleek, modern finishes compatible with residential and commercial projects.\r\n\r\nPower Outlets & USB Sockets – Functional, safe, and convenient solutions for everyday electrical needs.', 'Fashion Design', 'products/product_423_1.jpg', 'service', '[\"art\"]', 0, 0, 6, 0, 'approved', NULL, '2026-01-26 06:21:08', 194, '2026-01-26 06:17:17', '2026-02-04 08:05:01'),
(16, 232, 'غرفة نوم', 'رمضان يجمعنا… وبيتكم يستاهل الأجمل 🛋️\r\nاستقبلوا أجواء الشهر الفضيل بعروضنا الخاصة على الأثاث الأمريكي الفاخر \r\nخصومات تصل إلى 40% على تشكيلة واسعة من غرف النوم، غرف المعيشة, و طاولات المطبخ و السفرة و الوسط ✨\r\n🕰️ العرض ساري لفترة محدودة خلال شهر رمضان\r\n.\r\nللاستفسار تواصل معنا عن طريق:\r\nهاتف:022966426\r\nجوال/واتساب:+972592182553\r\nالعنوان:البيرة -شارع الارسال-مقابل شركة الكهرباء', 'Other', 'marketplace/541ba40e-7e6e-427d-9dab-b169bb427f0e.png', 'service', '[]', 0, 0, 15, 0, 'approved', NULL, '2026-02-04 05:30:09', 194, '2026-02-03 13:39:29', '2026-02-16 12:32:16'),
(17, 223, 'LED Lighting Solutions', 'Recessed LED Downlights – Energy-efficient, modern lighting ideal for ceilings in homes, offices, and showrooms.', 'Web Design', 'marketplace/51426601-996c-454f-8d1f-e793acca20a3.jpg', 'service', '[]', 0, 0, 0, 0, 'approved', NULL, '2026-02-12 04:57:59', 194, '2026-02-10 11:19:04', '2026-02-12 04:57:59'),
(18, 247, 'Bedrooms', 'Size & Dimensions: Usually requires a minimum floor area (often 70–80 square feet) and a ceiling height of at least 7 feet.', 'Graphic Design', 'products/product_484_1.png', 'service', '[]', 0, 0, 4, 0, 'approved', NULL, '2026-02-12 04:57:59', 194, '2026-02-12 04:57:37', '2026-02-14 07:51:47');
