(360, 205, 'كراسي بار', 'كراسي عالية تناسب البارات أو مطابخ الجزيرة، مريحة وأنيقة، مصممة للاستخدام الطويل مع دعم جيد للظهر.', 'Furniture', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, '2026-01-19 12:16:38', 194, '2026-01-19 10:37:00', '2026-02-04 03:05:13', 2),
(361, 206, 'أطقم كنب', 'أطقم جلوس متكاملة بتصاميم عصرية وكلاسيكية، مناسبة للمنازل والمساحات التجارية، توفر الراحة والمتانة مع خيارات متعددة من الأقمشة والألوان.', 'Sofas & Seating', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, '2026-01-19 12:16:38', 194, '2026-01-19 11:46:15', '2026-01-19 13:14:26', 1),
(362, 206, 'كراسي فردية', 'كراسي منفردة أنيقة للاستخدام في الصالونات، غرف الانتظار أو المكاتب، تجمع بين التصميم المريح والمظهر الجذاب.', 'Sofas & Seating', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, '2026-01-19 12:16:38', 194, '2026-01-19 11:47:11', '2026-02-19 19:32:23', 11),
(363, 206, 'طاولات وسط وجانبية', 'طاولات عملية توضع في غرف المعيشة أو المساحات المفتوحة، مثالية لوضع الضيافة والديكور، متوفرة بتصاميم وأحجام مختلفة.', 'Furniture', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, '2026-01-19 12:16:38', 194, '2026-01-19 11:48:01', '2026-01-19 13:14:25', 1),
(364, 206, 'طاولات سفرة', 'طاولات مخصصة لغرف الطعام والمطاعم، مصممة لتحمل الاستخدام اليومي، مع تنوع في الخامات مثل الخشب والزجاج والمعدن.', 'Dining Tables', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, '2026-01-19 12:16:38', 194, '2026-01-19 11:49:04', '2026-02-16 05:30:22', 4),
(365, 206, 'غرف نوم', 'غرف نوم رئيسية أو فندقية تشمل الأسرة والخزائن والكومودينو، مصممة لتوفير الراحة والهدوء مع لمسة جمالية مميزة.', 'Bedrooms', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, '2026-01-19 12:16:38', 194, '2026-01-19 11:51:47', '2026-02-16 05:02:10', 8),
(366, 206, 'مطابخ', 'مطابخ متكاملة وعملية، مصممة لتلبية جميع احتياجات المنزل والمطاعم، مع مراعاة الجودة، الجمالية، والمساحة المتاحة.\r\nالأنواع المتوفرة:\r\nمطابخ جاهزة / Modular Kitchens: وحدات مطبخية جاهزة يمكن تركيبها بسهولة، مع خزائن علوية وسفلية ومساحات تخزين ذكية.\r\nمطابخ حسب الطلب / Custom Kitchens: تصميم وتنفيذ حسب مساحة المطبخ، مع اختيار الألوان والخامات والديكور الداخلي حسب ذوق العميل.\r\nمطابخ جزيرة / Kitchen Islands: مناسبة للمساحات الكبيرة، توفر مساحة إضافية للعمل والطهي مع إمكانية وضع كراسي بار.', 'Kitchens', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, '2026-01-19 12:16:38', 194, '2026-01-19 11:53:45', '2026-02-17 19:11:27', 14),
(367, 206, 'كورنر', 'أرائك زاوية تجمع بين الأناقة والراحة، توفر مساحة جلوس كبيرة لعائلة أو لضيوف، وتلائم غرف المعيشة بمختلف أحجامها.', 'Sofas & Seating', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, '2026-01-21 05:13:02', 194, '2026-01-19 11:54:45', '2026-02-16 06:28:09', 15),
(368, 207, 'غرف نوم أطفال', 'غرف نوم أطفال بتصاميم عصرية وآمنة، تجمع بين الراحة والعملية لتناسب مختلف الأعمار. تشمل أسِرّة، خزائن، كومودينو وأحيانًا مكاتب دراسة، مع ألوان جذابة وخامات عالية الجودة تراعي سلامة الأطفال وتوفر مساحة تخزين ذكية.', 'Bedrooms', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, '2026-01-21 05:13:02', 194, '2026-01-19 17:06:59', '2026-01-21 05:13:02', 0),
(369, 207, 'مطابخ', 'مطابخ عصرية وعملية مصممة لتلبية احتياجات الاستخدام اليومي، تجمع بين الجودة العالية والتصميم الأنيق. تشمل وحدات تخزين علوية وسفلية، خزائن، وأسطح عمل متينة، مع خيارات متعددة من الألوان والخامات لتناسب مختلف المساحات والأذواق.', 'Kitchens', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, '2026-01-21 05:13:02', 194, '2026-01-19 17:15:06', '2026-02-11 21:17:35', 1),
(370, 207, 'غرف نوم', 'غرف نوم أنيقة وعملية تجمع بين الراحة والجمالية، مصممة لتوفير مساحة منظمة وهادئة للنوم والاسترخاء. تشمل الأسرة، خزائن، كومودينو، وأحيانًا تسريحات، مع خامات عالية الجودة وتصاميم تتناسب مع مختلف الأذواق والمساحات.', 'Bedrooms', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, '2026-01-21 05:13:02', 194, '2026-01-19 17:23:14', '2026-01-21 05:13:02', 0),
(371, 207, 'طاولات سفرة', 'طاولات سفرة عملية وأنيقة تناسب جميع المساحات، مصممة لتوفير راحة أثناء تناول الطعام ولتتناسب مع مختلف أساليب الديكور. متوفرة بأشكال وأحجام مختلفة، مصنوعة من خشب متين أو مواد حديثة عالية الجودة، ويمكن تنسيقها مع كراسي متناسقة.', 'Dining Tables', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, '2026-01-21 05:13:02', 194, '2026-01-19 17:25:39', '2026-01-21 05:13:02', 0),
(372, 207, 'أطقم كنب', 'أطقم كنب عصرية وكلاسيكية تناسب غرف المعيشة والمنازل والمكاتب، مصممة لتوفير أقصى درجات الراحة والأناقة. متوفرة بأحجام مختلفة مثل أطقم صغيرة، كبيرة، أو كورنر (زاوية)، مع خيارات متنوعة من الأقمشة والجلود، وتصاميم تجمع بين المتانة والجمالية.', 'Sofas & Seating', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, '2026-01-21 05:13:02', 194, '2026-01-19 17:27:33', '2026-01-21 05:13:02', 0),
(373, 207, 'دريسينج روم / Dressing Room', 'غرف ملابس مصممة لتنظيم الملابس والإكسسوارات بشكل أنيق وعملي، تشمل خزائن متعددة الأدراج، رفوف، مرايا، وأحيانًا مساحات لتخزين الأحذية والإكسسوارات. توفر الراحة وسهولة الوصول لكل القطع مع تصميم عصري يضيف لمسة جمالية للغرفة.', 'Dressing Room', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, '2026-01-21 05:13:02', 194, '2026-01-19 17:28:14', '2026-01-21 05:13:02', 0),
(374, 207, 'كراسي فردية', 'كراسي فردية أنيقة وعملية، مناسبة للجلوس في غرف المعيشة، الصالونات، غرف الاستقبال، أو المكاتب. مصممة لتوفير راحة مثالية ودعم للظهر، مع خامات عالية الجودة وتصاميم متنوعة تجمع بين الأناقة والمتانة.', 'Sofas & Seating', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, '2026-01-21 05:13:02', 194, '2026-01-19 17:31:15', '2026-02-17 14:52:36', 12),
(375, 207, 'طاولة وسط', 'طاولات وسط عملية وأنيقة توضع في غرف المعيشة أو الصالونات لتوفير مساحة لوضع المشروبات، المجلات، أو الديكورات. متوفرة بأشكال وأحجام مختلفة، مصنوعة من خشب متين، زجاج، أو مواد حديثة عالية الجودة، مع تصاميم تناسب جميع أساليب الديكور.', 'Coffee Table', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, '2026-01-21 05:13:02', 194, '2026-01-19 17:34:15', '2026-02-14 03:59:33', 10),
(376, 207, 'بيرو / Dressing Table with Mirror', 'بيروهات أنيقة وعملية مع مرايا مدمجة، مصممة لتسهيل الاستعداد اليومي وتنظيم مستلزمات التجميل والإكسسوارات. تشمل أدراج لتخزين أدوات التجميل والمجوهرات، مع تصميم عصري يجمع بين الجمال والوظيفة. متوفرة بخامات عالية الجودة تناسب غرف النوم المختلفة.', 'Dressing Table', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, '2026-01-21 05:13:02', 194, '2026-01-19 17:35:34', '2026-02-15 21:02:06', 11),
(377, 207, 'كراسي بار / Bar Stools', 'كراسي بار عالية وعصرية مناسبة للمطابخ، جزر المطبخ، البارات والمقاهي. مصممة لتوفير راحة أثناء الجلوس الطويل مع دعم جيد للظهر، ومتوفرة بتصاميم وألوان متعددة لتتناسب مع مختلف أنماط الديكور. خاماتها عالية الجودة لضمان المتانة وطول العمر.', 'Sofas & Seating', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, '2026-01-21 05:13:02', 194, '2026-01-19 17:38:18', '2026-02-07 18:10:17', 6),
(378, 207, 'مكاتب رسبشن / Reception Desks', 'مكاتب رسبشن أنيقة وعملية مصممة لاستقبال الزوار في المكاتب، الشركات، الفنادق، أو الصالات التجارية. توفر مساحة منظمة للعمل مع خزائن وأدراج لتخزين المستلزمات، مع تصميم عصري يعكس الاحترافية ويضفي جمالية على المدخل أو منطقة الاستقبال.', 'Reception Desks', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, '2026-01-21 05:13:02', 194, '2026-01-19 17:40:48', '2026-02-18 07:06:56', 10),
(379, 207, 'ديكور واجهة تلفزيون / TV Wall Units', 'وحدات ديكور لتجهيز واجهة التلفزيون بأناقة وعملية، تجمع بين التخزين والتنظيم مع التصميم العصري. تشمل رفوفاً، خزائن، وأماكن لعرض الديكورات أو الأجهزة الإلكترونية، مع خامات عالية الجودة وتصاميم تناسب غرف المعيشة بمختلف الأحجام والأساليب.', 'ديكور واجهة تلفزيون / TV Wall Units', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, '2026-01-21 05:13:02', 194, '2026-01-19 17:42:55', '2026-02-04 01:04:30', 8),
(380, 210, 'أرائك زاوية / كورنرات', 'أرائك زاوية تجمع بين الراحة، الأناقة، والاستغلال الذكي للمساحة، لتكون الحل الأمثل لغرف المعيشة والمساحات العائلية. تصميماتنا تأتي بأحجام وأنماط متعددة تناسب المساحات الصغيرة والكبيرة، مع خيارات متنوعة من الأقمشة والجلود عالية الجودة. توفر الكورنرات جلوسًا واسعًا ومريحًا، وتتميز بخيارات تنجيد متعددة وألوان عصرية تتناغم مع ديكور منزلك. بالإضافة إلى ذلك، بعض النماذج يمكن أن تتحول إلى سرير إضافي، مما يزيد من وظيفتها العملية في المنزل.', 'Furniture', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, '2026-01-21 05:13:02', 194, '2026-01-19 18:12:28', '2026-02-20 17:25:18', 34),
(381, 210, 'طاولات وسط / Coffee Tables', 'طاولات وسط عملية وأنيقة توضع في غرف المعيشة أو الصالونات لتوفير مساحة لوضع المشروبات، المجلات، الديكورات، أو الأجهزة الصغيرة. تأتي بتصاميم متعددة تناسب جميع أساليب الديكور، من الكلاسيكي إلى العصري، وبأحجام وأشكال مختلفة لتناسب المساحات الصغيرة والكبيرة. مصنوعة من مواد عالية الجودة مثل الخشب، الزجاج، أو المعدن لضمان المتانة وطول العمر.', 'Furniture', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, '2026-01-21 05:13:02', 194, '2026-01-19 18:12:28', '2026-02-07 06:38:34', 2),
(382, 210, 'أطقم كنب / Sofa Sets', 'أطقم كنب تجمع بين الأناقة والراحة، مثالية لغرف المعيشة والمنازل والمكاتب. تتوفر بتصاميم متنوعة من الكلاسيكي إلى العصري، مع أحجام مختلفة لتناسب المساحات الصغيرة والكبيرة، بما في ذلك الكورنر (أرائك زاوية). تأتي بخيارات متعددة من الأقمشة والجلود عالية الجودة، مع تنجيد مريح يدعم الجسم ويوفر تجربة جلوس مثالية. بعض النماذج قابلة للتحويل إلى سرير إضافي، مما يزيد من وظيفتها العملية.', 'Furniture', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, '2026-01-21 05:13:02', 194, '2026-01-19 18:12:28', '2026-02-13 09:48:40', 76),
(383, 210, 'طاولات وسط / Coffee Tables', 'تصميم أنيق وعصري يكمّل ديكور الغرفة.', 'Furniture', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, '2026-01-21 05:13:02', 194, '2026-01-19 18:12:28', '2026-02-07 06:20:09', 2),
(384, 210, 'إكسسوارات الأثاث / Furniture Accessories', 'إكسسوارات الأثاث عبارة عن قطع تكمل ديكور المنزل وتضيف لمسة عملية وجمالية لكل مساحة. تشمل مقابض وأزرار الخزائن، أرجل الكراسي والطاولات، أرفف إضافية، حوامل للمجلات والكتب، ومستلزمات تخزين ذكية. تم اختيار هذه الإكسسوارات لتوفير الراحة، تعزيز الوظائف العملية للأثاث، وإضفاء لمسة أناقة على التصميم الداخلي.', 'Furniture', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, '2026-01-21 05:13:02', 194, '2026-01-19 18:12:28', '2026-02-07 07:38:50', 5),
(385, 185, 'Ceramic tiled side table', '***طاولة دائرية***\r\nسم47 قطر*40سم📏\r\nخشب زان 🪵\r\nرجلين حديد🔩⁩', 'Furniture', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, '2026-01-21 05:13:02', 194, '2026-01-19 21:47:19', '2026-02-20 10:32:23', 10),
(386, 185, 'Ceramic tiled garden table.', '***طاولة حديقة***\r\nسم30*سم30*سم40📏\r\nحديد🔩', 'Furniture', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, '2026-01-21 11:04:13', 194, '2026-01-19 22:00:58', '2026-02-07 07:04:24', 6),
(387, 211, 'غرف نوم', 'تضيف لمسة أنيقة لغرفة نومك، متوفرة بخامات خشبية عالية الجودة وألوان متنوعة تناسب ذوقك', 'Bedrooms', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, '2026-01-21 11:04:13', 194, '2026-01-21 06:34:20', '2026-02-05 20:43:18', 2),
(388, 211, 'غرف نوم أطفال', 'غرفة نوم أطفال بتصميم عصري ملائم للأطفال من عمر 4–12 سنة، بألوان جذابة وتصميمات آمنة ومريحة.', 'Bedrooms', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, '2026-01-21 11:04:13', 194, '2026-01-21 06:35:07', '2026-02-05 22:18:09', 2),
(389, 211, 'سفرة طعام (طاولة وكراسي)', 'تصميم أنيق وقوي لتحمل الاستخدام اليومي والمناسبات الخاصة', 'Dining Tables', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, '2026-01-21 11:04:13', 194, '2026-01-21 06:36:31', '2026-02-17 13:57:51', 2),
(390, 211, 'أطقم كنب', 'قطع جلسة مريحة وعصرية لمنطقة الاستقبال أو غرفة المعيشة', 'Sofas & Seating', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, '2026-01-21 11:04:13', 194, '2026-01-21 06:37:13', '2026-02-07 12:48:35', 8),
(391, 211, 'مطابخ خشبية', 'يمكنك طلب تفصيل قطع أثاث حسب مقاسات غرفة منزلك أو حسب أسلوب الديكور الذي تفضّله', 'Kitchens', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, '2026-01-21 11:04:13', 194, '2026-01-21 06:38:56', '2026-02-05 18:13:32', 1),
(392, 211, 'قواطع خشبية وديكورات', 'قواطع خشبية كلاسيكية أو عصرية تستخدم لتقسيم المساحات داخل المنزل أو المكتب، مثل فصل غرفة الجلوس عن غرفة الطعام، أو إنشاء منطقة خاصة في غرفة مفتوحة. تأتي على ألواح قابلة للطي يمكن ترتيبها بسهولة حسب احتياج المكان.', 'Furniture', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, '2026-01-21 11:04:13', 194, '2026-01-21 06:39:28', '2026-02-05 18:13:30', 1),
(394, 215, 'طاولات وسط', 'طاولات الوسط (أو coffee tables) هي قطع أثاث منخفضة تُوضع في منتصف الجلسة لتكون النقطة المحورية في غرفة الجلوس أو الصالة، تجمع بين الوظيفة والجمال في آنٍ واحد. تُستخدم لوضع المشروبات، الكتب، المجلات، الزين أو حتى الديكورات الصغيرة التي تكمّل أسلوب الغرفة.', 'Furniture', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, '2026-01-21 11:04:13', 194, '2026-01-21 10:00:47', '2026-02-17 17:06:40', 13),
(395, 215, 'غرف النوم', 'غرف النوم ليست مجرد مكان للنوم فقط، بل مساحة شخصية مريحة تجمع بين الاسترخاء، التنظيم، والجمال. أثاث غرف النوم يشمل قطعًا متعددة تعمل معًا لتوفير بيئة هادئة ومنسّقة تناسب كل أسلوب — من الكلاسيكي الراقي إلى العصري البسيط.', 'Bedrooms', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, '2026-01-21 11:04:13', 194, '2026-01-21 10:00:47', '2026-02-04 07:30:04', 2),
(396, 215, 'أطقم الكنب', 'أطقم الكنب هي مجموعة متناسقة من مقاعد الجلوس تشمل غالبًا كنبة ثلاثية، كنبة ثنائية، وكرسي (أو أكثر)، مصمّمة لتوفير جلسة راقية ومريحة تُكمل ديكور غرفة المعيشة وتمنح الضيوف والعائلة مكانًا مثاليًا للاسترخاء والتواصل.', 'Sofas & Seating', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, '2026-01-21 11:04:13', 194, '2026-01-21 10:00:47', '2026-02-03 07:54:29', 4),
(397, 215, 'سرير الأطفال', 'سرير آمن ومريح لطفلك منذ الولادة حتى مرحلة الرضاعة، مصمم خصيصًا ليمنح حماية، راحة، وهدوء أثناء النوم والراحة. يأتي بتشطيبات ناعمة، جوانب محكمة ومتينة، ومساحة مناسبة لمرتبة مريحة تدعم نوم الطفل بشكل صحي.', 'Bedrooms', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, '2026-01-21 12:31:41', 194, '2026-01-21 10:05:44', '2026-02-20 14:40:30', 8),
(398, 215, 'طاولة السفرة', 'طاولة السفرة هي قطعة أثاث أساسية في كل منزل تُستخدم لتناول الطعام والتجمّع حوله، وتجمع بين الوظيفة والأناقة. تصميمها لا يضيف فقط لمسة ديكور راقية لفراغ السفرة، بل يوفّر مساحة مريحة ومرنة لتناول الوجبات وتبادل الأحاديث الممتعة مع الأحباب.', 'Dining Tables', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, '2026-01-21 12:31:41', 194, '2026-01-21 10:31:49', '2026-02-15 02:15:19', 3),
(399, 215, 'بيرو مع مرآة', 'بيرو مع مرآة هو طاولة أنيقة متعددة الاستخدامات تُضاف إلى غرفة النوم أو غرفة الضيوف، توفر مساحة مريحة للعمل، الدراسة، أو التزيّن في قطعة واحدة. تصميمه يجمع بين سطح واسع للعمل أو وضع المكياج ومرآة أنيقة تكمل شكل الغرفة وتمنحها إحساسًا أوسع وأكثر إشراقًا.', 'Furniture', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, '2026-01-21 12:31:41', 194, '2026-01-21 10:32:48', '2026-02-16 05:11:54', 12),
(400, 215, 'كرسي فردي', 'الكرسي الفردي هو قطعة أثاث عملية وجمالية تُستخدم بشكل منفصل عن أطقم الجلوس، ليكون إضافة مميّزة في غرفة المعيشة، غرفة النوم، أو حتى زاوية القراءة. يتميز بتصميمه الأنيق وحجمه المناسب الذي يوفّر راحة عالية دون شغل مساحة كبيرة.', 'Sofas & Seating', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, '2026-01-21 12:31:41', 194, '2026-01-21 10:36:42', '2026-02-04 05:06:47', 2),
(401, 217, 'غرف النوم الكاملة', 'تشمل سرير، دواليب، تسريحة، وطاولات جانبية بتشطيبات متناسقة تضفي مظهرًا منسّقًا وهادئًا على غرفة النوم، مع خامات قوية وتصميمات عصرية.', 'Bedrooms', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, '2026-01-22 10:07:34', 194, '2026-01-21 11:02:50', '2026-02-04 02:40:31', 2);
INSERT INTO `products` (`id`, `designer_id`, `title`, `description`, `category`, `image`, `features`, `rating`, `reviews_count`, `downloads`, `likes_count`, `featured`, `approval_status`, `rejection_reason`, `approved_at`, `approved_by`, `created_at`, `updated_at`, `views_count`) VALUES
(402, 217, 'أطقم الجلوس (صالونات / كنبات)', 'أطقم جلوس متعددة المقاعد بتصاميم مودرن وكلاسيك تناسب غرفة المعيشة، تجمع بين راحة التنجيد وأسلوب أنيق يكمّل ديكور بيتك، مع خيارات ألوان متعددة لتنسجم مع الديكور.', 'Sofas & Seating', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, '2026-01-21 12:31:41', 194, '2026-01-21 11:02:50', '2026-02-04 02:29:31', 4),
(403, 217, 'طاولات سفرة وكراسي', 'طاولات سفرة بمقاسات مختلفة مع كراسي مريحة، مصمّمة لتوفير جلسة طعام جميلة في بيتك وتجعل مائدة الطعام نقطة تجمع مريحة وعملية.', 'Dining Tables', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, '2026-01-22 10:07:34', 194, '2026-01-21 11:02:50', '2026-02-04 02:33:45', 2),
(404, 217, 'غرف نوم الأطفال', 'غرف نوم الأطفال هي مساحة خاصة تجمع بين الراحة، الأمان، والإبداع، مصمّمة خصيصًا لتلبية احتياجات الطفل اليومية من النوم، اللعب، والتعلّم في بيئة مريحة وجذابة. اختيار الأثاث المناسب في غرفة الطفل يساعد في خلق جو مليء بالبهجة والحيوية مع مراعاة سلامة واستدامة الاستخدام طوال السنوات الأولى من عمره.', 'Bedrooms', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, '2026-01-22 10:07:34', 194, '2026-01-21 11:02:50', '2026-02-04 02:33:54', 2),
(405, 217, 'بيرو/دريسنج مع مرآة', 'قطع جاهزة لتكملة غرف النوم أو الزوايا الخاصة بالاستعداد، تجمع بين وظيفة التخزين واللمسة الجمالية بوجود المرآة.', 'Furniture', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, '2026-01-22 10:07:34', 194, '2026-01-21 11:02:50', '2026-02-04 02:27:45', 2),
(406, 217, 'الكراسي الفردية', 'الكراسي الفردية هي قطعة أثاث متعددة الاستخدامات تُضفي لمسة جمالية وعملية في أي مكان في المنزل، من غرفة المعيشة وغرفة النوم إلى الشرفة أو المكتب. تصميمها المريح وحجمها المناسب يجعلها خيارًا ممتازًا لكل مساحة تحتاج راحة خاصة ولمسة ديكور أنيقة.', 'Sofas & Seating', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, '2026-01-22 10:07:34', 194, '2026-01-21 11:06:19', '2026-02-14 12:57:30', 28),
(407, 218, 'أطقم الكنب', 'أطقم الكنب هي قلب غرفة المعيشة، تجمع بين الراحة والأناقة وتضفي لمسة جمالية على أي مساحة. يتم تصميمها لتناسب مختلف الأحجام والاحتياجات، سواء للعائلات الكبيرة أو للمساحات الصغيرة.', 'Sofas & Seating', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, '2026-01-22 10:07:34', 194, '2026-01-21 12:18:52', '2026-02-19 03:24:09', 3),
(408, 218, 'طاولات السفرة', 'طاولات السفرة ليست مجرد قطعة أثاث، بل قلب غرفة الطعام التي تجمع العائلة والأصدقاء. تقدم مجموعة متنوعة من التصاميم لتناسب جميع المساحات والأذواق.', 'Dining Tables', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, '2026-01-22 10:07:34', 194, '2026-01-21 12:18:52', '2026-02-05 19:44:35', 2),
(409, 218, 'غرف الأطفال', 'غرف الأطفال تجمع بين الأمان، الراحة، والإبداع لتوفير بيئة مثالية للنوم، اللعب، والدراسة.', 'Bedrooms', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, '2026-01-22 10:07:34', 194, '2026-01-21 12:18:52', '2026-02-06 23:50:00', 2),
(410, 218, 'طاولات الوسط', 'طاولات الوسط هي القطعة المثالية لإكمال ديكور غرفة المعيشة، حيث تجمع بين الأناقة والوظيفة العملية. تأتي بتصاميم متعددة لتتناسب مع مختلف أنواع الكنب والصالونات، سواء كانت كلاسيكية أو عصرية.', 'Furniture', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, '2026-01-22 10:07:34', 194, '2026-01-21 12:18:52', '2026-02-07 05:51:09', 2),
(411, 218, 'بيرو مع مرآة', 'البيرو مع المرآة هو حل مثالي لتوفير وظيفة عملية وأناقة مميزة في غرف النوم أو غرف المعيشة. يجمع بين مساحة للعمل أو كتابة الملاحظات وإطلالة مرآة لتسهيل استخدامه اليومي.', 'Furniture', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, '2026-01-22 10:07:34', 194, '2026-01-21 12:18:52', '2026-02-07 08:03:09', 2),
(412, 219, 'طاولات الوسط', 'طاولات الوسط قطعة أساسية لإكمال ديكور غرفة المعيشة، حيث تجمع بين الأناقة والوظيفة العملية.', 'Furniture', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, '2026-01-22 10:07:34', 194, '2026-01-21 12:29:55', '2026-02-10 00:48:33', 3),
(413, 219, 'غرف نوم الأطفال', 'غرف نوم الأطفال تجمع بين الأمان، الراحة، والإبداع لتوفير بيئة مثالية للنوم، اللعب، والدراسة.', 'Bedrooms', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, '2026-01-22 10:07:34', 194, '2026-01-21 12:29:55', '2026-02-10 03:10:49', 3),
(414, 219, 'دريسينج روم', 'الدريسينج روم هي مساحة متكاملة لتنظيم الملابس والإكسسوارات، تجمع بين الراحة، الأناقة، والعملية لتسهيل الحياة اليومية.', 'Furniture', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, '2026-01-22 10:07:34', 194, '2026-01-21 12:29:55', '2026-02-04 02:57:09', 2),
(415, 219, 'غرف النوم', 'غرف النوم هي قلب المنزل، حيث الراحة والأناقة تلتقيان لتوفير بيئة هادئة ومريحة للنوم والاسترخاء.', 'Bedrooms', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, '2026-01-22 10:07:34', 194, '2026-01-21 12:29:55', '2026-02-04 02:05:32', 2),
(416, 219, 'أطقم الكنب', 'أطقم الكنب هي قلب غرفة المعيشة، حيث تجمع بين الراحة، الأناقة، والوظيفة العملية لتوفير مساحة مريحة للاسترخاء والتواصل مع العائلة والأصدقاء.', 'Sofas & Seating', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, '2026-01-22 10:07:34', 194, '2026-01-21 12:29:55', '2026-02-04 01:41:47', 2),
(417, 222, 'Sofas & Sectionals', 'Plush, modern, and built for comfort — from classic three‑seat sofas to modular sectionals that fit any space.', 'Sofas & Seating', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, '2026-01-22 10:07:34', 194, '2026-01-22 09:33:51', '2026-02-18 02:50:41', 14),
