(420, 222, 'Beds & Headboards', 'From minimal modern frames to upholstered plush designs — dreamy comfort every night.', 'Bedrooms', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, '2026-01-22 10:07:34', 194, '2026-01-22 09:59:10', '2026-02-05 01:07:47', 2),
