(422, 223, 'LED Lighting Solutions', 'Recessed LED Downlights – Energy-efficient, modern lighting ideal for ceilings in homes, offices, and showrooms.', 'Lighting', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, NULL, NULL, '2026-01-22 10:24:30', '2026-02-19 09:40:43', 14),
(423, 223, 'Switches & Sockets', 'Designer Wall Switches – Sleek, modern finishes compatible with residential and commercial projects.\r\n\r\nPower Outlets & USB Sockets – Functional, safe, and convenient solutions for everyday electrical needs.', 'Lighting', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, NULL, NULL, '2026-01-22 10:24:30', '2026-02-04 09:33:05', 6),
