(425, 213, 'LIVING ROOM', 'The living room is designed as a welcoming and comfortable space where aesthetics meet everyday functionality. Our living room furniture combines refined design, quality materials, and thoughtful proportions to create balanced interiors that feel both warm and contemporary. Each piece is carefully selected to enhance the atmosphere of the space, offering comfort, elegance, and a timeless sense of style.', 'Sofas & Seating', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, NULL, NULL, '2026-01-24 11:01:52', '2026-02-19 08:10:36', 18),
(426, 213, 'BEDROOM', 'The bedroom is a personal retreat designed for comfort, calm, and balance. Our bedroom furniture blends soft aesthetics with high-quality materials to create serene and inviting spaces. Each piece is thoughtfully selected to support relaxation while maintaining a refined, timeless design that reflects both functionality and understated elegance.', 'Bedrooms', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, NULL, NULL, '2026-01-24 11:05:20', '2026-02-04 09:32:08', 10),
(427, 213, 'DININNG TABLE', 'Dining tables are designed as the heart of shared moments and everyday gatherings. Our dining table collections combine strong craftsmanship, quality materials, and balanced proportions to create pieces that are both functional and visually refined. Each table is thoughtfully selected to enhance the dining experience, bringing warmth, durability, and timeless elegance to the space.', 'Dining Tables', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, NULL, NULL, '2026-01-24 11:06:44', '2026-02-16 22:27:56', 3),
(428, 213, 'TABLE', 'Coffee tables are essential elements that complete the living space and bring balance to the overall design. Our coffee table collection features refined forms, quality materials, and thoughtful detailing, creating pieces that are both practical and visually distinctive. Each table is carefully selected to add character, functionality, and a subtle touch of elegance to the space.', 'Furniture', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, NULL, NULL, '2026-01-24 11:08:39', '2026-02-07 14:15:51', 11),
(429, 213, 'KITCHEN DESIGN', 'Kitchen design is approached as a balance between functionality and refined aesthetics. Our kitchens are thoughtfully designed to maximize efficiency, organization, and ease of use, while maintaining a clean and modern visual identity. Through careful material selection, smart layouts, and attention to detail, each kitchen becomes a practical yet elegant space that supports everyday living.', 'Kitchens', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, NULL, NULL, '2026-01-24 11:09:42', '2026-02-18 02:24:18', 17),
(430, 216, 'EXTERIOR SETTING', 'Outdoor seating combines comfort, durability, and style to enhance any outdoor space.\r\nOur collections are crafted with high-quality materials that withstand the elements while maintaining elegance and functionality. Each piece is designed to create inviting spaces for relaxation, gatherings, and unforgettable moments outdoors.', 'Designing', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, NULL, NULL, '2026-01-24 11:27:13', '2026-02-17 07:30:17', 3),
(431, 216, 'TABLE', 'Center tables are the perfect blend of style and functionality.\r\nDesigned to complement any living space, our tables combine high-quality materials with thoughtful design details. They serve as a focal point for gatherings, adding elegance, practicality, and personality to your home.', 'Architecture', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, NULL, NULL, '2026-01-24 11:28:17', '2026-02-01 15:54:11', 2),
(432, 216, 'SOFA', 'Our sofa sets combine comfort, style, and quality for the perfect living space.\r\nEach set is thoughtfully designed with attention to detail, using premium materials to ensure durability and elegance. They create inviting areas for relaxation, conversation, and memorable moments with family and friends.', 'Sofas & Seating', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, NULL, NULL, '2026-01-24 11:29:24', '2026-02-02 07:17:43', 3),
(433, 216, 'BEDROOOM', 'Our bedroom collections are designed for comfort, style, and serenity.\r\nEach piece is crafted with attention to detail, high-quality materials, and timeless design. They create restful, elegant spaces where functionality meets sophisticated aesthetics, making every bedroom a personal sanctuary.', 'Bedrooms', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, NULL, NULL, '2026-01-24 11:30:20', '2026-02-02 04:01:33', 3),
(434, 216, 'DINING TABLE', 'Our dining tables are designed to bring people together in style and comfort.\r\nCrafted with high-quality materials and attention to detail, each table combines functionality with elegance. They create the perfect setting for meals, conversations, and memorable moments with family and friends.', 'Dining Tables', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, NULL, NULL, '2026-01-24 11:32:11', '2026-02-14 13:51:43', 3),
(435, 222, 'Bedroom – Innovative & High-Demand', 'Storage Beds (Hydraulic or Drawers)\r\nStrong metal mechanism + wooden finish.\r\nHeadboards with Integrated Features\r\nLED lights, side shelves, USB charging.\r\nModular Wardrobes\r\nCustomizable units (open/closed, sliding doors).\r\nVanity Desk + Mirror Combo\r\nCompact, modern, with hidden storage.\r\nKids Growing Beds\r\nExtendable beds that grow with the child.', 'Bedrooms', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, NULL, NULL, '2026-01-25 06:20:46', '2026-02-13 07:36:24', 16),
