(476, 232, 'طاولات سفرة', 'مضان يجمعنا… وبيتكم يستاهل الأجمل 🛋️\r\nاستقبلوا أجواء الشهر الفضيل بعروضنا الخاصة على الأثاث الأمريكي الفاخر \r\nخصومات تصل إلى 40% على تشكيلة واسعة من غرف النوم، غرف المعيشة, و طاولات المطبخ و السفرة و الوسط ✨\r\n🕰️ العرض ساري لفترة محدودة خلال شهر رمضان\r\n.\r\nللاستفسار تواصل معنا عن طريق:\r\nهاتف:022966426\r\nجوال/واتساب:+972592182553\r\nالعنوان:البيرة -شارع الارسال-مقابل شركة الكهرباء', 'Dining Tables', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, NULL, NULL, '2026-02-03 12:59:05', '2026-02-17 13:44:45', 11),
(475, 232, 'غرف نوم', 'رمضان يجمعنا… وبيتكم يستاهل الأجمل 🛋️\r\nاستقبلوا أجواء الشهر الفضيل بعروضنا الخاصة على الأثاث الأمريكي الفاخر \r\nخصومات تصل إلى 40% على تشكيلة واسعة من غرف النوم، غرف المعيشة, و طاولات المطبخ و السفرة و الوسط ✨\r\n🕰️ العرض ساري لفترة محدودة خلال شهر رمضان\r\n.\r\nللاستفسار تواصل معنا عن طريق:\r\nهاتف:022966426\r\nجوال/واتساب:+972592182553\r\nالعنوان:البيرة -شارع الارسال-مقابل شركة الكهرباء', 'Bedrooms', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, NULL, NULL, '2026-02-03 12:57:40', '2026-02-07 15:46:09', 6),
(443, 232, 'اطقم كنب', 'مجموعات من الأرائك والكراسي المصممة لتكمل بعضها في غرفة الجلوس', 'Sofas & Seating', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, NULL, NULL, '2026-02-03 08:43:22', '2026-02-04 05:04:55', 2),
(444, 239, 'bed rooms', '✨ إذا كنت تبحث عن لمسة فخامة وراحة في بيتك، فإن مفروشات محمد أبو سلطان في بيت لحم هي وجهتك المثالية. غرف النوم لديهم تجمع بين التصميم العصري والأناقة الكلاسيكية، مع استخدام أجود أنواع الخشب والتشطيبات الفاخرة. ستجد سريرًا مريحًا، خزانة ملابس عملية، وطاولات جانبية أنيقة، وكل ذلك بتفصيل يناسب ذوقك ومساحة منزلك. المعرض يقدم خيارات متنوعة تناسب جميع الأذواق، إضافة إلى خدمة التوصيل والتركيب ومعاملة راقية تجعل تجربة الشراء سهلة وممتعة.', 'Bedrooms', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, NULL, NULL, '2026-02-03 08:51:40', '2026-02-05 21:27:56', 4),
(445, 239, 'غرف الجلوس', '🌟 في مفروشات محمد أبو سلطان ستجد غرف جلوس تجمع بين الراحة والأناقة، حيث تتنوع التصاميم بين الكلاسيكي الفخم والعصري الحديث لتناسب جميع الأذواق. الأثاث مصنوع من أجود المواد مع تشطيبات عالية الجودة، ويشمل الأرائك المريحة، الطاولات الجانبية، والمكتبات الأنيقة التي تضفي لمسة جمال على أي منزل. المعرض يقدم خيارات متعددة من غرف جلوس متكاملة، مع إمكانية التفصيل حسب الطلب لتناسب مساحة بيتك وأسلوبك الخاص، إضافة إلى خدمة التوصيل والتركيب ومعاملة راقية تجعل تجربة الشراء ممتعة وسهلة.', 'Furniture', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, NULL, NULL, '2026-02-03 08:53:34', '2026-02-11 19:51:45', 4),
(446, 239, 'الصالونات', 'في مفروشات محمد أبو سلطان ستجد أجمل تشكيلات الصالونات التي تضفي لمسة فخامة على بيتك. التصاميم تجمع بين الراحة والأناقة، مع أرائك واسعة ومريحة، طاولات وسط وجانبية أنيقة، وألوان عصرية أو كلاسيكية تناسب جميع الأذواق. كل قطعة مصنوعة من أجود المواد وبحرفية عالية لتدوم طويلاً وتمنحك تجربة جلوس مميزة مع العائلة والضيوف. المعرض يقدم خيارات متعددة مع إمكانية التفصيل حسب الطلب، إضافة إلى خدمة التوصيل والتركيب ومعاملة راقية تجعل اختيارك للصالون تجربة ممتعة وسهلة.', 'Sofas & Seating', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, NULL, NULL, '2026-02-03 08:55:33', '2026-02-04 05:16:07', 4),
(447, 239, 'غرف نوم للاطفال', 'في مفروشات محمد أبو سلطان ستجد غرف نوم أطفال مصممة لتجمع بين الراحة والمرح، حيث تأتي بألوان زاهية ورسومات مبهجة تناسب شخصية طفلك وتضفي جوًا من الحيوية على الغرفة. التصاميم تشمل أسِرّة عملية (مفرد أو طابقين)، خزائن ملابس ملونة، ومكاتب دراسة أنيقة تساعد الأطفال على التنظيم والإبداع. كل قطعة مصنوعة من مواد آمنة ومتينة لتدوم طويلًا وتمنحك راحة البال. المعرض يوفر خيارات متعددة مع إمكانية التفصيل حسب الطلب لتناسب مساحة بيتك وذوق أطفالك، إضافة إلى خدمة التوصيل والتركيب ومعاملة راقية تجعل تجربة الشراء م', 'Bedrooms', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, NULL, NULL, '2026-02-03 08:57:18', '2026-02-05 22:26:20', 4),
(448, 239, 'مطبخ', '🍴 في مفروشات محمد أبو سلطان ستجد مطابخ عملية وأنيقة مصممة لتجمع بين الجمال والوظيفة، حيث يتم استخدام أجود أنواع الخشب والمواد المقاومة لتمنحك مطبخًا يدوم طويلًا ويجعل تجربة الطهي ممتعة وسهلة. التصاميم متوفرة بألوان عصرية وكلاسيكية لتناسب جميع الأذواق، مع إمكانية التفصيل حسب مساحة بيتك واحتياجاتك الخاصة.', 'Kitchens', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, NULL, NULL, '2026-02-03 09:01:14', '2026-02-12 06:26:09', 4),
(449, 239, 'طاولة سفرة', 'طاولات السفرة فهي مصممة لتكون مركزًا للدفء العائلي والضيافة، حيث تتنوع بين الطاولات الخشبية الفخمة والطاولات الحديثة ذات اللمسات الزجاجية أو المعدنية، مع كراسي مريحة تضفي لمسة أناقة على غرفة الطعام. كل قطعة تتميز بجودة عالية وتشطيبات متقنة تجعلها مثالية للاستخدام اليومي أو المناسبات الخاصة.', 'Dining Tables', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, NULL, NULL, '2026-02-03 09:03:16', '2026-02-05 21:23:18', 4),
(450, 206, 'Evil sofa', 'Evil Sofa Set – Where Luxury Meets Bold Modernity\r\n\r\nThe Evil sofa set is a refined expression of modern luxury, defined by sharp architectural lines and a commanding presence. Crafted for those with a taste for exclusivity, it blends sophisticated minimalism with a bold attitude that elevates any interior.\r\nPremium materials, exceptional comfort, and meticulous detailing come together to create a statement piece that speaks of confidence, elegance, and timeless modern design.', 'Furniture', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, NULL, NULL, '2026-02-03 09:09:55', '2026-02-16 06:07:28', 3),
(451, 206, 'Dining table', 'Marble- grey surface with a soft, elegant shine.\r\nBlack steel legs.\r\nSmooth Italian extension system - open one side or both, effortlessly.\r\nA table that adapts to your moments, quietly luxurious.\r\nDimensions: 206 x 103 cm\r\nTwo 45 cm extensions\r\nExpands up to 296 cm', 'Furniture', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, NULL, NULL, '2026-02-03 09:15:06', '2026-02-13 19:21:44', 9),
(452, 237, 'bed rooms', 'في مفروشات الأمل ستجد غرف نوم أنيقة تجمع بين الراحة والجمال، حيث تتنوع التصاميم لتناسب جميع الأذواق سواء كنت تبحث عن الطابع العصري البسيط أو الكلاسيكي الفخم. كل غرفة نوم مصنوعة من أجود أنواع الخشب والمواد المتينة، وتشمل سريرًا مريحًا، خزانة ملابس عملية، وطاولات جانبية تضفي لمسة من الفخامة على المكان. كما يوفر المعرض إمكانية التفصيل حسب الطلب لتناسب مساحة بيتك وذوقك الخاص، إضافة إلى خدمة التوصيل والتركيب ومعاملة راقية تجعل تجربة الشراء سهلة وممتعة.', 'Bedrooms', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, NULL, NULL, '2026-02-03 09:20:33', '2026-02-04 08:00:37', 2),
(453, 237, 'غرفة جلوس', '🛋️ في مفروشات الأمل ستجد غرف جلوس أنيقة مصممة لتمنح بيتك لمسة من الفخامة والراحة. الأرائك تأتي بأشكال وألوان متنوعة لتناسب جميع الأذواق، سواء كنت تبحث عن الطابع العصري البسيط أو الكلاسيكي الفخم. كما تتوفر طاولات وسط وجانبية بتصاميم راقية تضيف جمالًا عمليًا للمكان، مع استخدام مواد عالية الجودة تضمن المتانة وطول العمر. كل غرفة جلوس مصممة لتكون مركزًا للراحة والضيافة، حيث تجمع بين الأناقة والوظيفة لتجعل جلساتك مع العائلة والأصدقاء أكثر متعة.', 'Furniture', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, NULL, NULL, '2026-02-03 09:23:51', '2026-02-16 12:03:03', 9),
(454, 237, 'غرف نوم للاطفال', '🌈 في مفروشات الأمل ستجد غرف نوم أطفال مليئة بالحيوية والمرح، حيث تأتي بتصاميم مبتكرة وألوان زاهية تناسب شخصية طفلك وتضفي جوًا من البهجة على الغرفة. تشمل التشكيلة أسِرّة عملية (مفرد أو طابقين)، خزائن ملابس ملونة، ومكاتب دراسة أنيقة تساعد الأطفال على التنظيم والإبداع. كل قطعة مصنوعة من مواد آمنة ومتينة لتمنحك راحة البال وتدوم طويلًا، مع إمكانية التفصيل حسب الطلب لتناسب مساحة بيتك وذوق أطفالك. إضافة إلى ذلك، يوفر المعرض خدمة التوصيل والتركيب ومعاملة راقية تجعل تجربة الشراء سهلة وممتعة.', 'Bedrooms', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, NULL, NULL, '2026-02-03 09:26:30', '2026-02-04 07:47:42', 2),
(455, 237, 'صالون', 'في مفروشات الأمل ستجد أجمل تشكيلات الصالونات التي تضفي لمسة فخامة وأناقة على بيتك. التصاميم تجمع بين الراحة والذوق الرفيع، مع أرائك واسعة ومريحة، طاولات وسط وجانبية أنيقة، وألوان متنوعة تناسب جميع الأذواق سواء كنت تبحث عن الطابع العصري الحديث أو الكلاسيكي الراقي. كل قطعة مصنوعة من أجود المواد وبحرفية عالية لتدوم طويلًا وتمنحك تجربة جلوس مميزة مع العائلة والضيوف. كما يوفر المعرض خدمة التوصيل والتركيب ومعاملة راقية تجعل اختيارك للصالون تجربة سهلة وممتعة', 'Sofas & Seating', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, NULL, NULL, '2026-02-03 09:29:40', '2026-02-04 05:24:30', 1),
(456, 228, 'كراسي اطفال', '🪑 في The Room Decor ستجد كراسي أطفال أنيقة وعملية مصممة لتمنح طفلك الراحة والأمان، مع ألوان زاهية ورسومات مبهجة تضفي جوًا من المرح على الغرفة. الكراسي مصنوعة من مواد عالية الجودة وآمنة للأطفال، وتتوفر بأشكال متعددة تناسب غرف النوم أو غرف اللعب وحتى طاولات الدراسة. كما أن التصاميم تجمع بين الجمال والوظيفة لتساعد الأطفال على الجلوس براحة أثناء اللعب أو التعلم، مع إمكانية اختيار الألوان والتفاصيل بما يتناسب مع ذوقك ومساحة بيتك.', 'Furniture', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, NULL, NULL, '2026-02-03 09:44:16', '2026-02-17 00:40:32', 11),
(457, 228, 'تصاميم خشبية', 'في The Room Decor ستجد سكملات خشبية أنيقة تضيف لمسة دفء طبيعية وفخامة إلى بيتك. التصاميم تشمل طاولات جانبية، وحدات تلفاز، مكتبات، وقطع ديكور صغيرة مصنوعة من أجود أنواع الخشب وبحرفية عالية. هذه السكملات تأتي بألوان وتشطيبات متنوعة لتناسب جميع الأذواق.', 'Wood Works', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, NULL, NULL, '2026-02-03 09:51:01', '2026-02-20 15:35:43', 13),
(458, 228, 'كنب', 'في The Room Decor ستجد تشكيلات كنب أنيقة تجمع بين الراحة والفخامة، حيث تتنوع التصاميم لتناسب جميع الأذواق سواء كنت تبحث عن الطابع العصري الحديث أو الكلاسيكي الراقي. الكنب مصنوع من أجود المواد مع تشطيبات متقنة تضمن المتانة وطول العمر، كما يتوفر بألوان وأقمشة متعددة لتكمل ديكور غرفة الجلوس أو الصالون بشكل متناغم. كل قطعة مصممة لتمنحك جلسات مريحة مع العائلة والأصدقاء وتضفي لمسة جمالية على منزلك، مع خدمة التوصيل والتركيب التي تجعل تجربة الشراء سهلة وممتعة.', 'Furniture', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, NULL, NULL, '2026-02-03 09:57:18', '2026-02-10 19:37:11', 7),
(459, 228, 'dining tables', 'في The Room Decor ستجد طاولات طعام أنيقة تجمع بين الفخامة والعملية، حيث تتنوع التصاميم لتناسب جميع الأذواق سواء كنت تبحث عن الطابع العصري الحديث أو الكلاسيكي الراقي. الطاولات مصنوعة من أجود أنواع الخشب والمواد المتينة، مع تشطيبات عالية الجودة تضمن المتانة وطول العمر. كما تتوفر بأحجام مختلفة لتناسب المساحات الكبيرة والصغيرة، وتأتي مع كراسي مريحة تضفي لمسة جمالية على غرفة الطعام. كل قطعة مصممة لتكون مركزًا للدفء العائلي والضيافة، وتجعل جلسات الطعام أكثر متعة وأناقة.', 'Dining Tables', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, NULL, NULL, '2026-02-03 10:00:21', '2026-02-09 02:32:11', 7),
(460, 229, 'bed rooms', '🛏️ في ميداس ستجد غرف نوم أنيقة تجمع بين الراحة والفخامة، حيث تتنوع التصاميم لتناسب جميع الأذواق سواء كنت تبحث عن الطابع العصري الحديث أو الكلاسيكي الراقي. كل غرفة نوم مصنوعة من أجود المواد وبحرفية عالية، وتشمل سريرًا مريحًا، خزائن ملابس عملية، وطاولات جانبية تضفي لمسة جمالية على المكان. كما تتوفر خيارات متعددة من الألوان والأحجام لتناسب مختلف المساحات، مع خدمة التوصيل والتركيب التي تجعل تجربة الشراء سهلة وممتعة.', 'Bedrooms', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, NULL, NULL, '2026-02-03 10:13:06', '2026-02-19 16:52:27', 11),
(461, 229, 'غرفة جلوس', '🛋️ في ميداس ستجد غرف جلوس أنيقة تجمع بين الراحة والفخامة، حيث تتنوع التصاميم لتناسب جميع الأذواق سواء كنت تبحث عن الطابع العصري الحديث أو الكلاسيكي الراقي. الأرائك مصنوعة من أجود المواد مع تشطيبات متقنة تضمن المتانة وطول العمر، كما تتوفر بألوان وأقمشة متعددة لتكمل ديكور منزلك بشكل متناغم. بالإضافة إلى ذلك، توفر غرف الجلوس طاولات وسط وجانبية أنيقة تضيف لمسة عملية وجمالية، لتجعل جلساتك مع العائلة والأصدقاء أكثر متعة وراحة.', 'Furniture', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, NULL, NULL, '2026-02-03 10:14:27', '2026-02-05 14:47:08', 2),
(462, 229, 'dining tables', '🍽️ في ميداس ستجد طاولات طعام أنيقة تجمع بين الفخامة والعملية، حيث تتنوع التصاميم لتناسب جميع الأذواق سواء كنت تبحث عن الطابع العصري الحديث أو الكلاسيكي الراقي. الطاولات مصنوعة من أجود أنواع الخشب والمواد المتينة، مع تشطيبات عالية الجودة تضمن المتانة وطول العمر. كما تتوفر بأحجام مختلفة لتناسب المساحات الكبيرة والصغيرة، وتأتي مع كراسي مريحة تضفي لمسة جمالية على غرفة الطعام. كل قطعة مصممة لتكون مركزًا للدفء العائلي والضيافة، وتجعل جلسات الطعام أكثر متعة وأناقة', 'Dining Tables', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, NULL, NULL, '2026-02-03 10:18:26', '2026-02-17 09:51:07', 13),
(463, 229, 'صالون', '✨ في ميداس ستجد صالونات فخمة تجمع بين الأناقة والراحة، حيث تتنوع التصاميم لتناسب جميع الأذواق سواء كنت تبحث عن الطابع العصري الحديث أو الكلاسيكي الراقي. الأرائك مصنوعة من أجود المواد مع تشطيبات متقنة تضمن المتانة وطول العمر، كما تتوفر بألوان وأقمشة متعددة لتكمل ديكور منزلك بشكل متناغم. بالإضافة إلى ذلك، تتوفر طاولات وسط وجانبية أنيقة تضيف لمسة عملية وجمالية، لتجعل جلساتك مع العائلة والأصدقاء أكثر متعة وراحة. كل قطعة في صالونات ميداس مصممة لتكون مركزًا للضيافة والفخامة في بيتك.', 'Sofas & Seating', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, NULL, NULL, '2026-02-03 10:19:57', '2026-02-08 00:52:15', 7),
(464, 229, 'tv table', '📺 في ميداس ستجد طاولات تلفاز أنيقة وعملية تضيف لمسة جمالية إلى غرفة الجلوس أو الصالون. التصاميم تتنوع بين العصري البسيط والكلاسيكي الفخم، مع استخدام أجود أنواع الخشب والمواد المتينة لضمان الجودة وطول العمر. الطاولات مزودة بمساحات تخزين عملية للأجهزة والديكورات، وتتوفر بألوان وأحجام مختلفة لتناسب جميع المساحات والديكورات المنزلية. كل قطعة مصممة لتجمع بين الأناقة والوظيفة، وتجعل مشاهدة التلفاز أكثر تنظيمًا وراحة.\r\nيمكنني أن أكتب نسخة قصيرة جدًا ومباشرة تصلح كإعلان سريع على فيسبوك أو إنستغرام عن طا', 'TV Wall Units', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, NULL, NULL, '2026-02-03 10:23:53', '2026-02-04 07:10:48', 2),
(465, 234, 'كنب', '🪑 في High Fashion Furniture ستجد تشكيلات كنب وصالونات فاخرة تجمع بين التصميم العصري الراقي والراحة المطلقة. كل قطعة مصممة بعناية لتكون تحفة فنية تضيف لمسة من الفخامة إلى منزلك، مع استخدام أجود أنواع الأقمشة والمواد المتينة لضمان الجودة وطول العمر. الألوان والتفاصيل متوفرة بتنوع واسع لتناسب جميع الأذواق، سواء كنت تبحث عن الطابع الكلاسيكي الأنيق أو العصري الجريء. هذه التصاميم تجعل غرفة الجلوس أو الصالون مركزًا للضيافة والراحة، وتمنح بيتك شخصية مميزة تعكس ذوقك الرفيع.', 'Furniture', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, NULL, NULL, '2026-02-03 10:43:06', '2026-02-07 14:28:25', 6),
(466, 234, 'bed room', '🛏️ في High Fashion Furniture ستجد غرف نوم فاخرة تجمع بين التصميم العصري الراقي والراحة المطلقة. كل غرفة مصممة بعناية لتكون مساحة مثالية للاسترخاء، وتشمل سريرًا أنيقًا، خزائن ملابس عملية، وطاولات جانبية تضيف لمسة جمالية. المواد المستخدمة عالية الجودة مع تشطيبات متقنة تضمن المتانة وطول العمر، كما تتوفر خيارات متعددة من الألوان والأحجام لتناسب مختلف المساحات', 'Bedrooms', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, NULL, NULL, '2026-02-03 10:44:58', '2026-02-17 05:48:43', 11),
(467, 234, 'صالون', '🛋️ في High Fashion Furniture ستجد صالونات فاخرة تجمع بين التصميم العصري الأنيق والراحة المطلقة. الأرائك مصنوعة من أجود المواد مع تشطيبات متقنة تضمن الجودة وطول العمر، كما تتوفر بألوان وأقمشة متنوعة لتناسب جميع الأذواق. التصاميم تتميز بالتفاصيل الدقيقة التي تضفي لمسة فخامة على المكان، وتأتي مع طاولات وسط وجانبية أنيقة تكمل المشهد العام. كل صالون مصمم ليكون مركزًا للضيافة والدفء العائلي، ويمنح منزلك شخصية مميزة تعكس ذوقك الرفيع', 'Furniture', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, NULL, NULL, '2026-02-03 10:47:31', '2026-02-16 11:43:02', 9),
(468, 234, 'طاولة طعام', '🍽️ في High Fashion Furniture ستجد طاولات طعام فاخرة تجمع بين التصميم العصري الراقي والعملية. التصاميم مصنوعة من أجود أنواع الخشب والمواد المتينة، مع تشطيبات أنيقة تضفي لمسة فخامة على غرفة الطعام. الطاولات تتوفر بأحجام مختلفة لتناسب المساحات الكبيرة والصغيرة، وتأتي مع كراسي مريحة بتصاميم متناسقة تجعل جلسات الطعام أكثر أناقة ودفئًا. كل قطعة مصممة لتكون مركزًا للضيافة العائلية وتضيف لمسة جمالية مميزة إلى منزلك.', 'Dining Tables', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, NULL, NULL, '2026-02-03 10:50:34', '2026-02-07 12:44:31', 5),
(469, 234, 'dining tables', 'طاولة العزائم تُعتبر من أهم قطع الأثاث في أي منزل، فهي ليست مجرد مكان لتناول الطعام، بل مركز للضيافة واللقاءات العائلية. عادةً ما تكون كبيرة الحجم لتستوعب عددًا أكبر من الأشخاص، وتأتي بتصاميم فاخرة تجمع بين العملية والأناقة. تصنع غالبًا من أجود أنواع الخشب أو الزجاج مع تشطيبات متقنة، وتُرفق بكراسي مريحة تضفي لمسة جمالية متناسقة.\r\nطاولة العزائم تضيف هيبة خاصة لغرفة الطعام، وتجعل المناسبات والولائم أكثر تنظيمًا ودفئًا، فهي قطعة تجمع العائلة والأصدقاء حولها وتترك انطباعًا راقيًا لدى الضيوف.', 'Dining Tables', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, NULL, NULL, '2026-02-03 10:54:16', '2026-02-05 17:27:46', 2),
(470, 235, 'bed rooms', '🛏️ في Saray ستجد غرف نوم فاخرة تجمع بين التصميم العصري الأنيق والراحة المطلقة. كل غرفة مصممة بعناية لتكون مساحة مثالية للاسترخاء، وتشمل سريرًا مريحًا، خزائن ملابس عملية، وطاولات جانبية تضيف لمسة جمالية. المواد المستخدمة عالية الجودة مع تشطيبات متقنة تضمن المتانة وطول العمر، كما تتوفر خيارات متعددة من الألوان والأحجام لتناسب مختلف المساحات والديكورات. هذه الغرف تمنح منزلك أجواء من الفخامة والدفء، وتضفي شخصية مميزة تعكس ذوقك الرفيع.', 'Bedrooms', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, NULL, NULL, '2026-02-03 11:05:18', '2026-02-15 13:28:03', 8),
(471, 235, 'غرفة جلوس', '🛋️ غرفة الجلوس هي المساحة التي تجمع العائلة والأصدقاء، وتُعتبر قلب المنزل النابض بالحياة. تصميمها يعتمد على تحقيق التوازن بين الراحة والأناقة، حيث تضم عادة الأرائك أو الكنب، الطاولات الوسطية والجانبية، إضافة إلى الإكسسوارات مثل السجاد، الستائر، واللوحات الفنية التي تضفي لمسة شخصية على المكان.\r\nغرف الجلوس الحديثة تميل إلى الألوان المحايدة والخطوط البسيطة مع لمسات من الألوان الجريئة لإبراز الحيوية، بينما التصاميم الكلاسيكية تتميز بالتفاصيل المزخرفة والأقمشة الفاخرة مثل المخمل والحرير. اختيار غرفة', 'Furniture', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, NULL, NULL, '2026-02-03 11:07:09', '2026-02-19 11:20:32', 10),
(472, 235, 'dining tables', '🍽️ في Saray ستجد طاولات طعام فاخرة تجمع بين الأناقة والعملية، حيث تتنوع التصاميم لتناسب جميع الأذواق سواء كنت تبحث عن الطابع العصري الحديث أو الكلاسيكي الراقي. الطاولات مصنوعة من أجود أنواع الخشب والمواد المتينة مع تشطيبات عالية الجودة، وتتوفر بأحجام مختلفة لتناسب المساحات الكبيرة والصغيرة. كما تأتي مع كراسي مريحة بتصاميم متناسقة تجعل جلسات الطعام أكثر دفئًا وأناقة، لتكون مركزًا مثاليًا للعزائم واللقاءات العائلية.\r\nيمكنني أن أكتب نسخة دعائية قصيرة جدًا ومباشرة تصلح كإعلان سريع على فيسبوك أو إنست', 'Dining Tables', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, NULL, NULL, '2026-02-03 11:10:34', '2026-02-14 08:59:28', 3),
(473, 235, 'صالة', '🛋️ في Saray ستجد صالونات فاخرة تجمع بين الأناقة والراحة، حيث تتنوع التصاميم لتناسب جميع الأذواق سواء كنت تبحث عن الطابع العصري الحديث أو الكلاسيكي الراقي. الأرائك مصنوعة من أجود المواد مع تشطيبات متقنة تضمن الجودة وطول العمر، كما تتوفر بألوان وأقمشة متنوعة لتكمل ديكور منزلك بشكل متناغم. التصاميم تتميز بالتفاصيل الدقيقة التي تضفي لمسة فخامة على المكان، وتأتي مع طاولات وسط وجانبية أنيقة تكمل المشهد العام. كل صالون مصمم ليكون مركزًا للضيافة والدفء العائلي، ويمنح منزلك شخصية مميزة تعكس ذوقك الرفيع.', 'Furniture', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, NULL, NULL, '2026-02-03 11:12:22', '2026-02-19 23:19:58', 11),
(474, 232, 'غرف نوم', 'رمضان يجمعنا… وبيتكم يستاهل الأجمل 🛋️\r\nاستقبلوا أجواء الشهر الفضيل بعروضنا الخاصة على الأثاث الأمريكي الفاخر \r\nخصومات تصل إلى 40% على تشكيلة واسعة من غرف النوم، غرف المعيشة, و طاولات المطبخ و السفرة و الوسط ✨\r\n🕰️ العرض ساري لفترة محدودة خلال شهر رمضان\r\n.\r\nللاستفسار تواصل معنا عن طريق:\r\nهاتف:022966426\r\nجوال/واتساب:+972592182553\r\nالعنوان:البيرة -شارع الارسال-مقابل شركة الكهرباء', 'Furniture', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, NULL, NULL, '2026-02-03 12:43:51', '2026-02-14 08:59:49', 3),
(477, 232, 'طاولات سفرة', 'مضان يجمعنا… وبيتكم يستاهل الأجمل 🛋️\r\nاستقبلوا أجواء الشهر الفضيل بعروضنا الخاصة على الأثاث الأمريكي الفاخر \r\nخصومات تصل إلى 40% على تشكيلة واسعة من غرف النوم، غرف المعيشة, و طاولات المطبخ و السفرة و الوسط ✨\r\n🕰️ العرض ساري لفترة محدودة خلال شهر رمضان\r\n.\r\nللاستفسار تواصل معنا عن طريق:\r\nهاتف:022966426\r\nجوال/واتساب:+972592182553\r\nالعنوان:البيرة -شارع الارسال-مقابل شركة الكهرباء', 'Dining Tables', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, NULL, NULL, '2026-02-03 13:00:48', '2026-02-18 13:03:01', 12),
(478, 238, 'bed rooms', 'مفروشات المدينة تقدم لكم أحدث تشكيلات غرف النوم العصرية والفاخرة، بتصاميم تركية وصينية وأوروبية تناسب جميع الأذواق. نحرص على الجودة العالية والخامات الممتازة مع عروض وخصومات موسمية مميزة. سواء كنت تبحث عن غرفة نوم للعرائس أو لتجديد منزلك، ستجد لدينا خيارات متنوعة تجمع بين الفخامة والراحة لتمنحك تجربة استثنائية', 'Bedrooms', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, NULL, NULL, '2026-02-04 04:01:34', '2026-02-15 05:52:04', 2),
(479, 238, 'مطبخ', 'مفروشات المدينة تقدم لكم تشكيلات مطابخ عصرية وعملية بتصاميم متنوعة من الألمنيوم والخشب والمطابخ الجاهزة، مع إمكانية التنفيذ حسب الطلب لتناسب جميع المساحات والأذواق. نحرص على الجودة العالية والخامات الممتازة، ونوفر خيارات حديثة تجمع بين الأناقة والوظيفة لتمنحكم تجربة مميزة في مطبخكم. سواء كنتم تبحثون عن مطبخ جاهز سريع التركيب أو تصميم خاص يعكس شخصيتكم، ستجدون لدينا الحلول المثالية التي تجمع بين الراحة والجمال', 'Kitchens', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, NULL, NULL, '2026-02-04 04:03:58', '2026-02-20 12:45:37', 9),
(480, 238, 'غرفة جلوس', 'غرفة الجلوس في قلب المدينة تبدو كواحة هادئة وسط صخب الشوارع، جدرانها مزينة بألوان دافئة ونوافذها الكبيرة تسمح بدخول الضوء الطبيعي ليغمر المكان بالراحة. الأرائك البسيطة المرتبة بعناية تمنح شعورًا بالترتيب والسكينة، بينما الطاولات الصغيرة تضيف لمسة عملية دون أن تثقل الجو. المساحة خالية من العر، مما يجعلها أكثر انفتاحًا ومرونة، وكأنها دعوة للاسترخاء والتأمل بعيدًا عن ازدحام الخارج.', 'Furniture', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, NULL, NULL, '2026-02-04 04:05:37', '2026-02-15 05:51:27', 3),
(481, 238, 'صالة', 'صالون المدينة يتميز بأجواء أنيقة وعصرية، حيث تتوزع المقاعد المريحة حول طاولات صغيرة تمنح المكان لمسة من الحميمية والدفء. الإضاءة الناعمة تنعكس على الجدران المزينة بألوان هادئة، مما يخلق بيئة مثالية للاسترخاء أو تبادل الأحاديث. المساحة منظمة بعناية وبدون ذكر أسعار، لتبقى الصورة وصفية خالصة تركز على جمال المكان وانسيابية تفاصيله، وكأنها دعوة للاستمتاع بجمال الصالون دون أي انشغال آخر.', 'Furniture', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, NULL, NULL, '2026-02-04 04:07:20', '2026-02-04 09:19:32', 2),
(484, 247, 'Bedrooms', 'Size & Dimensions: Usually requires a minimum floor area (often 70–80 square feet) and a ceiling height of at least 7 feet.', 'Bedrooms', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, NULL, NULL, '2026-02-12 04:55:09', '2026-02-20 12:32:59', 12),
(485, 247, 'Dinning tables', 'a central piece of furniture designed for gathering to share meals, conversation, and other activities.', 'Dining Tables', '', NULL, 0.00, 0, 0, 0, 0, 'approved', NULL, NULL, NULL, '2026-02-12 04:55:09', '2026-02-20 12:17:30', 2);
