(1, 'designer', 244, 'designer', 245, '2026-02-04 05:54:39', '2026-02-04 05:54:39');
INSERT INTO `projects` (`id`, `designer_id`, `category_id`, `title`, `image`, `featured`, `approval_status`, `rejection_reason`, `approved_at`, `approved_by`, `likes_count`, `views_count`, `comments_count`, `created_at`, `updated_at`, `description`, `role`, `category`, `likes`, `views`, `comments`) VALUES
(20, 31, 9, 'Kitchen Island Design (Revit)', 'projects/GMumlLvngDKaP1jC1WZHA2pUVQfdbtMAk7sxRDHO.jpg', 0, 'approved', NULL, '2026-01-08 10:41:29', 194, 0, 6, 0, '2025-11-26 12:14:40', '2026-02-18 04:25:27', 'Designed and modeled the kitchen island using Revit, including cabinetry, materials, and spatial layout', 'Interior Designer & Revit Modeler', NULL, 0, 0, 0),
(21, 33, 9, 'Schizophrenic Experience', 'projects/41mu5pxvzxXhr5Ey8TJBUJPKgGRYYIJ4e6o6X3Pe.png', 0, 'approved', NULL, '2026-01-08 10:41:29', 194, 0, 31, 0, '2025-11-26 19:27:29', '2026-02-18 17:29:27', 'How we mobile through spaces changes or perception. We are effected by the\r\nstrong impact our senses leave on us. The emotions we feel in a space can be derived from the forces of space elements.\r\nMy proposal aims to design through senses by creating an architectural journey, where the narrative\r\npushes and pulls at different emotions. In another words, to tell a story using different architectural characteristics. And so, the response of users changes accordingly.', 'Lead Designer', NULL, 0, 0, 0),
(22, 33, 9, 'Reawakening The Memory Of The City', 'projects/FJTZ0icInBmvtvs9h846WtfBuIk1yvQQJ7CgPGTx.png', 0, 'approved', NULL, '2026-01-08 10:41:22', 194, 0, 13, 0, '2025-11-26 19:27:29', '2026-02-16 15:38:17', 'Although we may never be able to recreate the perfect version of the memory (our memories are always vague, confusing and in conflict), we can stimulate it by relying on sensory perception. The gasometer reveals the inside world in the humans and hosts five environments, each readjust itself to accommodate intimate experiences of the memory. The project suggests different levels, the first, a place where memories can be deposited and shared with others (collective memory). The second, a place where secret memories can be stored (memory immortalization). The third place, where memories can be taken, to be destroyed, when the holder doesn’t want them any more (memory extraction).', 'Lead Designer', NULL, 0, 0, 0),
(23, 33, 9, 'The Body as The Main Character: Regenerating guest spaces in Middle-Eastern homes', 'projects/opY7qugrNpnbqPTXhWbgy9GydYiu8XicOI5fHmR0.png', 0, 'approved', NULL, '2026-01-08 10:41:22', 194, 0, 8, 0, '2025-11-26 19:27:29', '2026-02-12 13:06:43', 'Relationship between the costume and the body. it created a self-consciousness, a new awareness of how much of ourselves we may reveal through our moving bodies and how this may be highlighted or hidden by what we wear. This costume makes the body more comfortable with itself thus willing to take more risks and indulge more with the surrounding space. This will consequently enhance the relationship between the body and the environment. The costume will no more create a boundary between the skin and the surrounding, yet it will create a bridge between the body and environment thus enhancing both the internal and external bodily awareness.', 'Lead Designer', NULL, 0, 0, 0),
(24, 35, 9, 'Residential apartment design', 'projects/CEM6COQtHvrFwlDRfW0nk21cyMAHYEKPtyjZezlH.png', 0, 'approved', NULL, '2026-01-08 10:41:22', 194, 0, 20, 0, '2025-11-27 07:40:52', '2026-02-20 00:01:45', 'In the second year, first semester, we received a plan of about 105 square meters. I worked on zoning the space and creating the interior layout with proper distribution of rooms and furniture through hand drawn architectural sketches. The project included plans, elevations, sections, and 3D drawings that showed the full design clearly.', 'Interior design', NULL, 0, 0, 0),
(25, 35, 9, 'Innovative bedroom design', 'projects/dWxnAQHZ13J7esz7NKnPoqgtpzluSzNDmATyFpGo.png', 0, 'approved', NULL, '2026-01-08 10:41:22', 194, 0, 4, 0, '2025-11-27 07:40:52', '2026-02-11 12:42:46', 'In the third year, first semester, we designed an innovative space from the house. I chose the bedroom and developed a smart walk in closet system using Internet of Things. An iPad screen stores clothing by photo and suggests daily outfits. It tracks unused items and alerts the user to donate or recycle them. The room includes remote controlled features and smart functions that improve comfort.( Note, there are many other projects, but I selected two different ones to show my work, one manual and one digital.)', 'Interior design', NULL, 0, 0, 0),
(26, 41, 9, 'nutrition clinic', 'projects/lWKBdiEY4QJstsZ8LjyjOxRVKes0lRNenDRMR3Ud.jpg', 0, 'approved', NULL, '2026-01-08 10:41:22', 194, 0, 3, 0, '2025-11-28 10:24:07', '2026-01-29 06:04:37', 'Interior design for a nutrition clinic. Reception area.', 'medical center', NULL, 0, 0, 0),
(29, 48, 9, 'فيلا', 'projects/9rF1ft8B5EKJx5iggt2E9Q7AtgyFTudTVpUvzoeo.jpg', 0, 'approved', NULL, '2026-01-08 10:41:22', 194, 0, 4, 0, '2025-11-29 15:04:34', '2026-02-04 01:25:24', 'قمنا بتصميم هذه الفيلا داخليا وخارجيا بناء على معايير معينه وطراز مودرن حديث وتلبيه رغبات صاحب الفيلا', 'المصمم الرئيسي', NULL, 0, 0, 0),
(30, 48, 9, 'صالة استقبال', 'projects/bOv6gIiA8SNsRoHdGaf469km5DQWh7C36XNaP65S.jpg', 0, 'approved', NULL, '2026-01-08 10:41:22', 194, 0, 7, 0, '2025-11-29 15:04:34', '2026-02-15 05:36:54', 'قمنا بتصميم صاله استقبال صغيره ومناسبه وعلى نظام مودرن', 'المصمم الرئيسي', NULL, 0, 0, 0),
(31, 48, 9, 'غرفة نوم ماستر', 'projects/N97zDcAmg19fnjhHLIo8zVzj5z4dm6CbcjzpXOpL.jpg', 0, 'approved', NULL, '2026-01-08 10:41:22', 194, 0, 3, 0, '2025-11-29 15:04:34', '2026-02-03 21:51:44', 'كانت من اجمل الغرف التي قمنا بتصميمها واعتمدنا على اكثر من فكره غريبه وتم تنفيذها بشكل متقن ورهيب قمت بالاشراف على تنفيذها', 'المصمم الرئيسي', NULL, 0, 0, 0),
(46, 57, 9, 'Saif fitness project', 'projects/yrtKSkSA3taQ3a1tOqW07SEc0y5KqyRfFG3EtQaL.jpg', 0, 'approved', NULL, '2026-01-08 10:41:22', 194, 0, 4, 0, '2025-11-30 08:13:24', '2026-02-04 03:39:39', 'Lead the project from initial concept to final completion; budget, quality control, detailed construction drawings', 'Architect and interior design', NULL, 0, 0, 0),
(47, 57, 9, 'Shqair apartment', 'projects/l948g6cPPAdQdx2vc66SSk9NOmeRukoUPrFUtpap.jpg', 0, 'approved', NULL, '2026-01-08 10:41:22', 194, 0, 20, 0, '2025-11-30 08:13:24', '2026-02-10 23:27:50', 'Provide project management design and supervision services , select color schemes furniture fixtures and finishes create 3d visualization', 'Interior designer', NULL, 0, 0, 0),
(48, 57, 9, '2nd phase of a detailed comprehensive t master plan for Ramallah Al-Bireh urban area 15km', 'projects/gxi3qY4tYv2oRSZZdNaY8Ymx9rXw3kTiZqXibkJ7.jpg', 0, 'approved', NULL, '2026-01-08 10:41:22', 194, 0, 4, 0, '2025-11-30 08:13:24', '2026-02-04 09:29:08', 'Developed Multi-modal terminal hubs including central hubs pedestrians spaces BRT corridor planning', 'Key urban planner', NULL, 0, 0, 0),
(49, 59, 9, 'Palestinian tourist village', 'projects/Alxop7vizyAh96WIdTf9UeTvDbfygc72eYUzasVD.jpg', 0, 'approved', NULL, '2026-01-08 10:41:22', 194, 0, 3, 0, '2025-11-30 09:41:34', '2026-02-11 12:50:06', 'Palestinian tourist village', 'Interior designer', NULL, 0, 0, 0),
(50, 62, 9, 'Interior design & landscape', 'projects/AHGZqCVMePY8YH1gbwjaRYF78gygp58bEvVxOMxD.jpg', 0, 'approved', NULL, '2026-01-08 10:41:22', 194, 0, 2, 0, '2025-11-30 15:24:56', '2026-01-21 12:45:56', 'At our office we do design plans & 3d photos', 'Designer', NULL, 0, 0, 0),
(52, 64, 9, 'Villa1', 'projects/444d91f9-df1e-4d9d-9029-189f4c8c53d1.jpg', 0, 'approved', NULL, '2026-01-08 10:41:22', 194, 0, 2, 0, '2025-11-30 17:14:46', '2026-01-21 12:31:35', 'Villa in berizit', 'Design villa from out to inside', NULL, 0, 0, 0),
(53, 64, 9, 'Aradi muqaddasa interior offices', 'projects/b3425435-beba-450c-bd50-647c7249e82b.jpg', 0, 'approved', NULL, '2026-01-08 10:41:22', 194, 0, 2, 0, '2025-11-30 17:14:46', '2026-01-21 12:45:21', 'Design officese with tender documents', 'Interior design and tendering', NULL, 0, 0, 0),
(54, 64, 9, 'Landscspe', 'projects/7d7bb4da-380d-49b4-89ce-6d9d9e490487.jpg', 0, 'approved', NULL, '2026-01-08 10:41:22', 194, 0, 3, 0, '2025-11-30 17:14:46', '2026-02-04 06:14:42', 'Design pool with exterior elements', 'Design landscape', NULL, 0, 0, 0),
(55, 67, 9, 'Urban Apartment Interior & Custom Furniture Collection', 'projects/30a8808b-bbfc-4664-92e0-262349dd2724.jpeg', 0, 'approved', NULL, '2026-01-08 10:41:22', 194, 0, 5, 0, '2025-12-01 06:00:27', '2026-02-04 01:44:00', 'Led the full redesign of a modern office environment, focusing on enhancing workflow and employee comfort. Developed custom furniture pieces—including workstations, storage units, and meeting tables—tailored to the client’s brand identity. Oversaw material selection, detailed shop drawings, and coordination with carpenters and contractors. Delivered a functional, visually cohesive workspace with improved spatial efficiency', 'Lead Interior & Furniture Designer', NULL, 0, 0, 0),
(56, 67, 9, 'Residential Building Interior Development', 'projects/197cf76d-5c2c-4579-aa28-c711de598fda.jpeg', 0, 'approved', NULL, '2026-01-08 10:41:22', 194, 0, 4, 0, '2025-12-01 06:00:27', '2026-02-07 20:02:17', 'Led the interior design and space-planning for a multi-unit residential building, including lobby, corridors, and apartment layouts. Developed material palettes, lighting plans, and detailed interior elevations. Designed custom-built wardrobes, kitchen units, and integrated storage solutions for all units. Coordinated with architects, structural engineers, and contractors to ensure design consistency throughout the building', 'Interior Architect & Fit-Out Designer', NULL, 0, 0, 0),
(57, 69, 9, 'Kitchen', 'projects/106526c5-5e03-4972-8744-0498ab5015e1.jpeg', 0, 'approved', NULL, '2026-01-08 10:41:22', 194, 0, 3, 0, '2025-12-01 06:54:51', '2026-02-11 09:31:51', 'Executing kitchen and choosing all elements as client wants and as 3d designs \r\nmaking plans and shop drawings details for the kitchen and supervision', 'making all plan and shop drawings', NULL, 0, 0, 0),
(58, 69, 9, 'Guest room / all details done from building to furnishing', 'projects/2c932c43-c007-4545-a04a-9df56b1126e4.jpeg', 0, 'approved', NULL, '2026-01-08 10:41:22', 194, 0, 3, 0, '2025-12-01 06:54:51', '2026-02-13 11:10:36', 'making all drawings and designs and execution for the project', 'Planning / executing and supervision', NULL, 0, 0, 0),
(59, 71, 9, 'Project in Tayyib, Jerusalem', '', 0, 'approved', NULL, '2026-01-08 10:41:17', 194, 0, 3, 0, '2025-12-01 08:24:12', '2026-02-04 01:03:37', 'My task for this project was to design the kitchen, living room, entrance, and dining area to complement each other and create balance and cohesion, given their interconnected nature. This included creating 3D renderings of the space and selecting appropriate materials and colors.', 'Interior Architect', 'Architecture', 0, 0, 0),
(60, 71, 9, 'Project in Tayyib, Jerusalem', '', 0, 'approved', NULL, '2026-01-08 10:41:17', 194, 0, 17, 0, '2025-12-01 08:24:12', '2026-02-19 08:28:37', 'This project is still in progress, and my role in the design process is to design from scratch, creating spaces that are utilized correctly to suit the family\'s wishes, in addition to choosing colors and materials and rendering them in 3D.', 'Interior Architect', 'Architecture', 0, 0, 0),
(61, 71, 9, 'BedRoom', '', 0, 'approved', NULL, '2026-01-08 10:41:17', 194, 0, 4, 0, '2025-12-01 08:24:12', '2026-02-04 09:29:37', 'This project is part of the 3D Max course in 2024', '3D Rendering Specialist', 'Interior Design', 0, 0, 0),
(63, 71, 9, 'industrial design project', '', 0, 'approved', NULL, '2026-01-08 10:41:17', 194, 0, 4, 0, '2025-12-01 08:24:12', '2026-02-12 06:24:05', 'This design was for the Industrial Product course at the university and was a final project. The requirement was to create a design for a well-known brand with a function different from what this brand produces. Here I worked on showing the Burberry brand on a chessboard and designing the soldiers based on the shapes of Burberry accessories.', 'Designer', 'Architecture', 0, 0, 0),
(64, 72, 9, 'Choclates - Interior desgin project', 'projects/98b287cb-0ac5-413a-8496-b9b9be8cfcbf.jpg', 0, 'approved', NULL, '2026-01-08 10:41:17', 194, 0, 4, 0, '2025-12-01 08:26:55', '2026-02-07 23:27:27', 'Interior and façade design of a cake shop and production factory in Bethlehem. Designed from initial concept through execution while working as an architect at Architecture and Building Bureau.', 'Architect and interior designer', NULL, 0, 0, 0),
(65, 72, 9, 'Office interior design', 'projects/82daaeb3-315b-4faa-b106-49ba7a0111a3.jpg', 0, 'approved', NULL, '2026-01-08 10:41:17', 194, 0, 3, 0, '2025-12-01 08:26:55', '2026-02-19 16:38:22', 'Interior design of an office and kitchenette in Bethlehem. Designed from concept to 3D visualization and full detailed drawings while working as an architect at the Architecture and Building Bureau.', 'Architect and interior designer', NULL, 0, 0, 0),
