(224, 199, 10, 'المؤسسات', '', 0, 'approved', NULL, '2026-01-20 05:04:44', 194, 0, 12, 0, '2026-01-12 08:55:31', '2026-02-19 13:57:51', 'تزويد المؤسسات بأثاث مكتبي، خزائن، وحدات تخزين، مكاتب واستراحات موظفين. تنفيذ مشاريع مخصصة حسب احتياجات المؤسسة.', 'Services Provider', 'Other', 0, 0, 0),
(225, 199, 10, 'الشركات', '', 0, 'approved', NULL, '2026-01-22 10:07:27', 194, 0, 4, 0, '2026-01-12 08:55:31', '2026-02-13 16:18:14', 'تصميم وتوريد أثاث للشركات، مثل مكاتب إدارية، قاعات اجتماعات، وخزائن ملفات. التركيب في الموقع وضمان الجودة.', 'Services Provider', 'Other', 0, 0, 0),
(226, 199, 10, 'المحلات التجارية', '', 0, 'approved', NULL, '2026-01-20 05:04:44', 194, 0, 4, 0, '2026-01-12 08:55:31', '2026-02-07 00:49:25', 'واجهات عرض خشبية وزجاجية، رفوف عرض، وحدات تخزين للمنتجات، تصميم حسب هوية العلامة التجارية.', 'Services Provider', 'Other', 0, 0, 0),
(227, 200, 10, 'تجهيز المنازل السكنية بالإنارة', '', 0, 'approved', NULL, '2026-01-22 10:07:27', 194, 0, 32, 0, '2026-01-12 10:02:45', '2026-02-20 11:43:53', 'تركيب ثريات أكريليك وLED في الصالونات، غرف النوم، والمطابخ.\r\nتركيب أضواء مدمجة للحوائط والأسقف لإضفاء لمسة عصرية.\r\nتركيب إكسسوارات الإضاءة المكملة مثل المظلات والحوامل.', 'Services Provider', 'Other', 0, 0, 0),
(228, 200, 10, 'تجهيز المحلات التجارية', '', 0, 'approved', NULL, '2026-01-22 10:07:27', 194, 0, 10, 0, '2026-01-12 10:02:45', '2026-02-19 06:06:04', 'إنارة محل MAS للملابس (كمثال على مشاريعهم السابقة).\r\nتركيب أضواء LED للإعلانات الداخلية والخارجية.\r\nتركيب رفوف مضاءة وثريات لتسليط الضوء على المنتجات.', 'Services Provider', 'Other', 0, 0, 0),
(229, 200, 10, 'تجهيز المعارض والصالات', '', 0, 'approved', NULL, '2026-01-22 10:07:27', 194, 0, 17, 0, '2026-01-12 10:02:45', '2026-02-19 06:05:08', 'تركيب سبوتات وإنارة موجهة لتسليط الضوء على القطع المعروضة.\r\nتركيب أنظمة إنارة قابلة للتعديل حسب طبيعة العرض.\r\nاستخدام ثريات وملحقات لإضفاء جمالية فاخرة على المساحات الكبيرة.', 'Services Provider', 'Lightning', 0, 0, 0),
(230, 200, 10, 'تجهيز المؤسسات والشركات', '', 0, 'approved', NULL, '2026-01-22 10:07:27', 194, 0, 26, 0, '2026-01-12 10:02:45', '2026-02-20 07:23:10', 'تركيب إنارة LED مكتبية وعامة لضمان راحة العاملين.\r\nتركيب ثريات وأباجورات لمكاتب الإدارة وغرف الاجتماعات.\r\nتركيب أنظمة تحكم ذكية لتوفير الطاقة وتنظيم الإنارة.', 'Services Provider', 'Other', 0, 0, 0),
(231, 200, 10, 'مشاريع مخصصة', '', 0, 'approved', NULL, '2026-01-22 10:07:27', 194, 0, 10, 0, '2026-01-12 10:02:45', '2026-02-14 03:29:38', 'تصميم وتنفيذ حلول إنارة مخصصة للمطاعم والكافيهات.\r\nتركيب إنارة خارجية للحدائق والمداخل باستخدام مصابيح LED عالية الجودة.\r\nتنفيذ مشاريع إنارة معمارية تجمع بين الجمال والوظيفة.', 'Services Provider', 'Other', 0, 0, 0),
(232, 202, 10, 'مشروع تجهيز مناجر (ورش نجارة) بشكل كامل', '', 0, 'approved', NULL, '2026-01-22 10:07:27', 194, 0, 15, 0, '2026-01-13 08:59:19', '2026-02-09 21:38:55', 'مشروع تجهيز مناجر يهدف لإنشاء ورشة نجارة متكاملة مجهزة بأحدث الماكينات والمعدات الأساسية، لتلبية احتياجات الورش الصناعية والمحترفين. يتضمن المشروع كافة مناطق العمل من قص وتقطيع الخشب، تشكيل وتنعيم الأسطح، التجميع والدهان، وحتى تخزين المواد والأدوات.', 'Services Provider', 'Other', 0, 0, 0),
(234, 206, 9, 'تجهيز شقق سكنية كاملة', '', 0, 'approved', NULL, '2026-01-22 10:07:27', 194, 0, 13, 0, '2026-01-19 11:57:13', '2026-02-16 05:58:09', 'تصميم وتوريد أثاث غرف المعيشة، غرف النوم، المطابخ وغرف الطعام حسب مساحة المنزل واحتياجات العميل.', 'Services Provider', 'تجهيز شقق سكنية كاملة', 0, 0, 0),
(235, 206, 9, 'أثاث مطاعم وكافيهات', '', 0, 'approved', NULL, '2026-01-22 10:07:27', 194, 0, 3, 0, '2026-01-19 11:57:37', '2026-02-16 06:15:47', 'طاولات سفرة، كراسي سفرة، كراسي بار، وأرائك انتظار، مع تصاميم عملية وجمالية لتحمل الاستخدام المكثف.', 'Services Provider', 'أثاث مطاعم وكافيهات', 0, 0, 0),
(236, 206, 9, 'تجهيز صالات انتظار ومكاتب', '', 0, 'approved', NULL, '2026-01-22 10:07:27', 194, 0, 2, 0, '2026-01-19 11:57:56', '2026-02-16 05:56:29', 'أرائك زاوية، كراسي فردية، طاولات وسط، مكاتب، وطاولات اجتماعات للمكاتب والشركات.', 'Services Provider', 'تجهيز صالات انتظار ومكاتب', 0, 0, 0),
(237, 206, 9, 'مشاريع تجارية ومناطق عامة', '', 0, 'approved', NULL, '2026-01-22 10:07:27', 194, 0, 4, 0, '2026-01-19 11:59:21', '2026-02-16 06:17:13', 'أثاث مخصص للمساحات التجارية، مثل صالات الفنادق، قاعات المناسبات، والمعارض، مع تصميم يتناسب مع هوية المكان.', 'Services Provider', 'مشاريع تجارية ومناطق عامة', 0, 0, 0),
(238, 207, 9, 'تنفيذ فنادق', '', 0, 'approved', NULL, '2026-01-22 10:07:27', 194, 0, 2, 0, '2026-01-19 17:46:41', '2026-02-02 06:11:30', 'تجهيز الغرف، اللوبي، المطاعم، والصالات بالأثاث العصري والفخم مع مراعاة الراحة والجمالية والوظائف العملية.', 'Services Provider', 'Manufacturing', 0, 0, 0),
(239, 207, 9, 'مكاتب وشركات', '', 0, 'approved', NULL, '2026-01-22 10:07:27', 194, 0, 2, 0, '2026-01-19 17:47:33', '2026-02-02 07:32:34', 'تجهيز المكاتب وغرف الاجتماعات والاستقبال بمكاتب، كراسي، طاولات، ومكاتب رسبشن، مع التركيز على الإنتاجية والأناقة المهنية.', 'Services Provider', 'Manufacturing', 0, 0, 0),
(240, 207, 9, 'شقق سكنية', '', 0, 'approved', NULL, '2026-01-22 10:07:27', 194, 0, 2, 0, '2026-01-19 17:48:06', '2026-02-02 06:33:50', 'تجهيز الشقق بكل ما تحتاجه من أثاث عملي وجمالي، من غرف النوم والمطابخ إلى غرف المعيشة وغرف الطعام، مع تنسيق يناسب المساحة.', 'Services Provider', 'Manufacturing', 0, 0, 0),
(241, 211, 9, 'ورشة تنفيذ أثاث حسب الطلب', '', 0, 'approved', NULL, '2026-01-22 10:07:27', 194, 0, 4, 0, '2026-01-21 06:42:15', '2026-02-15 05:52:51', 'خدمة تصنيع أثاث مخصص بتصاميم فردية تلائم مساحات منازل العملاء وديكوراتهم.\r\nتصميمات حسب طلب العميل (غرف نوم – مطابخ – خزائن)\r\n\r\nاستخدام خامات مختلفة (خشب طبيعي – MDF – زجاج)\r\n\r\nتسليم وتركيب القطع داخل المنزل\r\nالفائدة: يستفيد العملاء من قطع فريدة وتناسب المساحات المحددة، ويمكنك البدء بمعدات ورشة صغيرة.', 'Services Provider', 'Architecture', 0, 0, 0),
(242, 211, 9, 'خدمات تصميم داخلي وديكور منزلي', '', 0, 'approved', NULL, '2026-01-22 10:07:27', 194, 0, 9, 0, '2026-01-21 06:42:46', '2026-02-15 06:59:57', 'تقديم استشارات تصميم داخلي للمنازل والمحلات التجارية مع اختيار الأثاث والألوان المناسبة.\r\nتصميم ثنائي/ثلاثي الأبعاد (ديكور الغرف – المعيشة – المطابخ)\r\n\r\nتوصيات بالأثاث من متجرك أو شركائك\r\n\r\nتنفيذ ديكورات مثل قواطع خشبية، وحدات تعليق، خلفيات تلفزيون\r\nالفائدة: يرتفع الطلب على تصميمات متناسقة، ويمكنك تقديم باقات خدمات (تصميم + تنفيذ).', 'Services Provider', 'Interior Design', 0, 0, 0),
(243, 211, 9, 'خدمات نقل وتركيب الأثاث', '', 0, 'approved', NULL, '2026-01-22 10:07:27', 194, 0, 9, 0, '2026-01-21 06:43:38', '2026-02-02 03:40:47', 'خدمة متكاملة لنقل الأثاث من المعرض إلى المنزل مع تركيب احترافي.\r\nفريق نقل محترف مع أدوات التغليف\r\nتركيب الأثاث في المكان المطلوب\r\nرفع ونقل القطع الثقيلة بين الطوابق\r\nالفائدة: خدمة إضافية تُرفع قيمة الطلب وتزيد من رضا العملاء.', 'Services Provider', 'Installation', 0, 0, 0),
(245, 222, 9, 'Residential Projects', '', 0, 'approved', NULL, '2026-01-22 10:07:27', 194, 0, 6, 0, '2026-01-22 10:04:01', '2026-02-01 17:50:38', 'Modern Family Homes – Complete furnishing solutions including living rooms, bedrooms, and dining areas, tailored to client style and space requirements.\r\n\r\nLuxury Apartments – High-end interior design with custom furniture pieces that maximize comfort and aesthetics.', 'Services Provider', 'Interior Design', 0, 0, 0),
(246, 222, 9, 'Commercial & Office Projects', '', 0, 'approved', NULL, '2026-01-22 10:07:27', 194, 0, 6, 0, '2026-01-22 10:04:56', '2026-02-03 05:27:43', 'Corporate Offices – Full office setup, including ergonomic workstations, meeting rooms, and collaborative spaces.\r\n\r\nCo-Working Spaces – Flexible, stylish furniture solutions designed for productivity and community.', 'Services Provider', 'Interior Design', 0, 0, 0),
(247, 222, 9, 'Outdoor & Landscaping Projects', '', 0, 'approved', NULL, '2026-01-22 10:07:27', 194, 0, 3, 0, '2026-01-22 10:06:13', '2026-02-17 13:53:20', 'Patio & Garden Furniture – Durable outdoor sets for private homes and public spaces, combining comfort with weather-resistant materials.\r\n\r\nCommunity Spaces – Seating and recreational furniture for parks, gardens, and communal area', 'Services Provider', 'Interior Design', 0, 0, 0),
(248, 223, 9, 'Smart Home & IoT Projects', '', 0, 'approved', NULL, NULL, NULL, 0, 3, 0, '2026-01-22 10:24:30', '2026-02-16 21:50:12', 'Residential Smart Systems – Installation of smart switches, plugs, and lighting controllers for connected homes.\r\n\r\nCommercial Smart Solutions – IoT-enabled lighting and electrical systems for efficiency, energy savings, and convenience.', 'Services Provider', 'Graphic Design', 0, 0, 0),
(249, 213, 9, 'RESEDENTIAL APARTMAENT', '', 0, 'approved', NULL, NULL, NULL, 0, 99, 0, '2026-01-24 11:00:34', '2026-02-18 20:08:55', 'Our furniture showroom is a curated space that brings together thoughtful design and high-quality craftsmanship. We present a selected range of furniture pieces designed to meet different lifestyles and spatial needs, with a strong focus on materials, details, and functionality. Each piece is carefully chosen to create balanced, timeless interiors that reflect both comfort and refined aesthetic value.', 'Lead Interior & Furniture Designer', 'General', 0, 0, 0),
(250, 216, 9, 'RESEDENTIAL', '', 0, 'approved', NULL, NULL, NULL, 0, 5, 0, '2026-01-24 11:22:11', '2026-02-19 06:05:30', 'Furniture is at the heart of every well-designed space.\r\nIt goes beyond function to shape the character, comfort, and identity of interiors. Each piece is selected with careful attention to quality, materials, and detail, ensuring a balance between aesthetics and practicality. Thoughtfully designed furniture enhances everyday living and creates spaces that feel both refined and welcoming.', 'Interior Designer', 'General', 0, 0, 0),
(253, 71, 9, 'Private Residential Interior Design', '', 0, 'approved', NULL, NULL, NULL, 1, 5, 0, '2026-02-01 22:12:43', '2026-02-12 04:56:44', 'This project involved the interior design of the kitchen, living room, and master bedroom as part of a private residential project, focusing on functionality, comfort, and cohesive design language.', 'Interior Architect', 'Architecture', 0, 0, 0);
