INSERT INTO `services` (`id`, `designer_id`, `name`, `description`, `category`, `approval_status`, `rejection_reason`, `approved_at`, `approved_by`, `image`, `created_at`, `updated_at`, `views_count`, `requests_count`) VALUES
(8, 32, 'Interior designer', 'I can handle all stages of the design process, from creating modboards and renderings to the necessary plans for project implementation.', 'Design', 'approved', NULL, '2026-01-08 11:10:33', 194, '', '2025-11-26 14:42:29', '2026-01-08 11:10:33', 0, 0),
(9, 32, 'Furniture design', 'I can handle all stages of furniture design, from providing consultations on available materials that meet your expectations, to creating the necessary plans for execution, including types of wood and assembly methods from the first screw to the final product.', 'Design', 'approved', NULL, '2026-01-08 11:10:33', 194, '', '2025-11-26 14:42:29', '2026-01-08 11:10:33', 0, 0),
(10, 35, 'Furniture and interior design', 'I provide interior and furniture design services with a focus on smart use of space. I create modern layouts with thoughtful material and color selection. I design smart, interactive, and multi use furniture that combines function with a contemporary look. My goal is to build comfortable and organized spaces that support the user and add value in every detail.', 'design', 'approved', NULL, '2026-01-08 11:10:33', 194, '', '2025-11-27 07:40:52', '2026-01-08 11:10:33', 0, 0),
(11, 41, 'Design and implementation of projects', 'Design and execution of engineering projects.\r\n\r\nHomes, shops, and gardens.\r\nPreparing engineering plans in all their forms', 'Design and implementation', 'approved', NULL, '2026-01-08 11:10:28', 194, 'services/service_11.jpg', '2025-11-28 10:24:07', '2026-01-08 11:10:28', 0, 0),
(15, 52, 'Indoor Environmental Quality Assessment', 'Whether it involves thermal, lightning, or IAQ issues, I provide IEQ assessments with reports before and after case improvements. Towards more sustainable indoors!', 'Concultancy', 'approved', NULL, '2026-01-08 11:10:28', 194, '', '2025-11-30 07:03:07', '2026-01-08 11:10:28', 0, 0),
(16, 52, 'Interior Design', 'After deep user-needs-assessment meetings, you will have the project of your dreams! design that fulfills your needs and requirements with a contemporary touch.', 'Design', 'approved', NULL, '2026-01-08 11:10:28', 194, '', '2025-11-30 07:03:07', '2026-01-08 11:10:28', 0, 0),
(17, 52, 'Archtitectural Desin', 'Architectural projects that combine function and aesthetics.', 'Design', 'approved', NULL, '2026-01-08 11:10:28', 194, '', '2025-11-30 07:03:07', '2026-01-08 11:10:28', 0, 0),
(19, 65, '3d modeling', 'make 3d model\r\nmake real model\r\nmake ing drawing\r\nand drawing', 'i cane help you for any think', 'approved', NULL, '2026-01-08 11:10:28', 194, 'services/service_19.png', '2025-11-30 17:22:07', '2026-01-08 11:10:28', 0, 0),
(20, 68, 'Interior design', 'floor plans - furniture layout - 3D visualizations - electrical and lighting plans - coordination with suppliers', 'Design', 'approved', NULL, '2026-01-08 11:10:28', 194, '', '2025-12-01 06:11:44', '2026-01-08 11:10:28', 0, 0),
(21, 68, 'Site supervision', 'regular site inspection - quality control and workmanship - approval of materials and finishes on site - addressing execution issues directly', 'Development/finishing supervision', 'approved', NULL, '2026-01-08 11:10:28', 194, '', '2025-12-01 06:11:44', '2026-01-08 11:10:28', 0, 0),
