(125, 157, 'Company Profiles', 'We design high-end corporate profiles that blend minimalist aesthetics with professional storytelling. Our layouts prioritize clarity and luxury, using realistic mockups to showcase your company\'s milestones and services. By balancing high-quality imagery with organized content, we help your business build immediate trust with investors and partners through a polished, authoritative presentation.', 'Graphic Design', 'approved', NULL, '2026-01-08 11:09:18', 194, NULL, '2025-12-17 10:59:38', '2026-01-08 11:09:18', 0, 0),
(126, 157, 'Creative Ad Campaigns', 'We develop innovative ad campaigns that turn logistical challenges into creative marketing opportunities. Our approach combines clever messaging with bold visuals to ensure your brand remains reliable and prominent. We focus on high-speed delivery concepts and tech-driven solutions to capture attention and demonstrate your brand\'s ability to provide consistent service under any circumstances.', 'Graphic Design', 'approved', NULL, '2026-01-08 11:09:18', 194, NULL, '2025-12-17 10:59:38', '2026-01-08 11:09:18', 0, 0),
(127, 157, 'Dynamic Social Ads.', 'We create vibrant, interactive social media content that seamlessly connects your products to a modern, healthy lifestyle. Our designs utilize energetic color palettes and clear calls-to-action to maximize engagement. By focusing on visual storytelling and interactive elements, we boost brand recall and ensure your message resonates effectively with your target audience across all digital platforms.', 'Graphic Design', 'approved', NULL, '2026-01-08 11:09:18', 194, NULL, '2025-12-17 10:59:38', '2026-01-08 11:09:18', 0, 0),
(128, 157, 'Brand Identity Systems', 'We build authoritative visual identities that merge industry-specific symbolism with modern design principles. Our process ensures total consistency across all touchpoints, from digital applications and smartphone interfaces to stationery and professional ID cards. We provide a unified visual language that reflects reliability and professional expertise, ensuring your brand stands out with a cohesive and powerful presence.', 'Graphic Design', 'approved', NULL, '2026-01-08 11:09:18', 194, NULL, '2025-12-17 10:59:38', '2026-01-08 11:09:18', 0, 0),
(129, 157, 'Premium Packaging & Labeling', 'We transform products into shelf-ready experiences using high-impact visuals and functional design. Our packaging solutions prioritize both safety and aesthetic appeal, using color psychology and detailed illustrations to highlight product benefits. We create engaging designs that enhance the unboxing experience and make your product the preferred choice for consumers through professional and creative labeling.', 'Graphic Design', 'approved', NULL, '2026-01-08 11:09:18', 194, NULL, '2025-12-17 10:59:38', '2026-01-08 11:09:18', 0, 0),
(130, 159, 'Custom Furniture Design & Manufacturing', 'Design and build tailor-made furniture for bedrooms, kitchens, living rooms, and offices.\r\nOptions for single beds, full bedroom sets, cabinets, shelves, and more.\r\nPersonalized finishes, sizes, and styles according to client requirements.', 'Design', 'approved', NULL, '2026-01-08 10:42:18', 194, NULL, '2025-12-17 11:53:03', '2026-01-08 10:42:18', 0, 0),
