(327, 234, 'توصيل وتركيب الأثاث', 'خدمة توصيل الأثاث إلى المنازل والمكاتب مع التركيب عند الطلب', 'Installation', 'approved', NULL, NULL, NULL, NULL, '2026-02-02 09:00:47', '2026-02-02 09:00:47', 0, 0),
(328, 235, 'استشارات تصميم داخلي', 'استشارات تصميم داخلي لمساعدة العملاء في اختيار الأثاث وتنظيم المساحات', 'Consultation', 'approved', NULL, NULL, NULL, NULL, '2026-02-02 09:31:29', '2026-02-02 09:31:29', 0, 0),
(329, 235, 'توصيل', 'توصيل وتركيب الأثاث إلى المنازل والمكاتب', 'Installation', 'approved', NULL, NULL, NULL, NULL, '2026-02-02 09:31:29', '2026-02-02 09:31:29', 0, 0),
(330, 235, 'تصنيع', 'إمكانية تصنيع بعض القطع حسب طلب العميل أو تعديل المقاسات والتصميم', 'Manufacturing', 'approved', NULL, NULL, NULL, NULL, '2026-02-02 09:31:29', '2026-02-02 09:31:29', 0, 0),
(331, 237, 'التصميم', 'محلات الأمل في العيزرية لا تقتصر خدماتها على تصنيع الأثاث فحسب، بل توفر أيضًا خدمة التوصيل والتركيب لضمان راحة الزبائن وسهولة الحصول على منتجاتهم بشكل كامل وجاهز للاستخدام. وتشمل هذه الخدمة نقل الأثاث إلى منازل العملاء بأمان، ثم القيام بتركيبه بدقة وفق المواصفات المطلوبة. إضافة إلى ذلك، يقدم المحل خدمة ما بعد البيع التي تتضمن المتابعة مع الزبون، وإجراء أي تعديلات أو تفصيل إضافي حسب الحاجة، مما يعكس التزامه بالجودة ورضا العملاء. هذه المنظومة المتكاملة من التصنيع إلى التوصيل والتركيب والتفصيل تجعل', 'Design', 'approved', NULL, NULL, NULL, NULL, '2026-02-02 09:55:11', '2026-02-02 09:55:11', 0, 0),
(332, 237, 'التصنيع', 'محلات الأمل في العيزرية لا تقتصر خدماتها على تصنيع الأثاث فحسب، بل توفر أيضًا خدمة التوصيل والتركيب لضمان راحة الزبائن وسهولة الحصول على منتجاتهم بشكل كامل وجاهز للاستخدام. وتشمل هذه الخدمة نقل الأثاث إلى منازل العملاء بأمان، ثم القيام بتركيبه بدقة وفق المواصفات المطلوبة. إضافة إلى ذلك، يقدم المحل خدمة ما بعد البيع التي تتضمن المتابعة مع الزبون، وإجراء أي تعديلات أو تفصيل إضافي حسب الحاجة، مما يعكس التزامه بالجودة ورضا العملاء. هذه المنظومة المتكاملة من التصنيع إلى التوصيل والتركيب والتفصيل تجعل', 'Manufacturing', 'approved', NULL, NULL, NULL, NULL, '2026-02-02 09:55:11', '2026-02-02 09:55:11', 0, 0),
(333, 237, 'اخدمة التوصيل', 'محلات الأمل في العيزرية لا تقتصر خدماتها على تصنيع الأثاث فحسب، بل توفر أيضًا خدمة التوصيل والتركيب لضمان راحة الزبائن وسهولة الحصول على منتجاتهم بشكل كامل وجاهز للاستخدام. وتشمل هذه الخدمة نقل الأثاث إلى منازل العملاء بأمان، ثم القيام بتركيبه بدقة وفق المواصفات المطلوبة. إضافة إلى ذلك، يقدم المحل خدمة ما بعد البيع التي تتضمن المتابعة مع الزبون، وإجراء أي تعديلات أو تفصيل إضافي حسب الحاجة، مما يعكس التزامه بالجودة ورضا العملاء. هذه المنظومة المتكاملة من التصنيع إلى التوصيل والتركيب والتفصيل تجعل', 'Other', 'approved', NULL, NULL, NULL, NULL, '2026-02-02 09:55:11', '2026-02-02 09:55:11', 0, 0),
(334, 237, 'خدمة ما بعد البيع', 'محلات الأمل في العيزرية لا تقتصر خدماتها على تصنيع الأثاث فحسب، بل توفر أيضًا خدمة التوصيل والتركيب لضمان راحة الزبائن وسهولة الحصول على منتجاتهم بشكل كامل وجاهز للاستخدام. وتشمل هذه الخدمة نقل الأثاث إلى منازل العملاء بأمان، ثم القيام بتركيبه بدقة وفق المواصفات المطلوبة. إضافة إلى ذلك، يقدم المحل خدمة ما بعد البيع التي تتضمن المتابعة مع الزبون، وإجراء أي تعديلات أو تفصيل إضافي حسب الحاجة، مما يعكس التزامه بالجودة ورضا العملاء. هذه المنظومة المتكاملة من التصنيع إلى التوصيل والتركيب والتفصيل تجعل', 'Other', 'approved', NULL, NULL, NULL, NULL, '2026-02-02 09:55:11', '2026-02-02 09:55:11', 0, 0),
(335, 238, 'تصميم داخلي مخصص', 'مساعدة العملاء في اختيار أفضل التصاميم والألوان لتتناسب مع مساحة المنزل وذوقهم الشخصي.', 'Design', 'approved', NULL, NULL, NULL, NULL, '2026-02-02 10:13:45', '2026-02-02 10:13:45', 0, 0),
(336, 238, 'توصيل وتركيب الأثاث', 'خدمة التوصيل السريع مع تركيب جميع القطع في المنزل بشكل محترف', 'Installation', 'approved', NULL, NULL, NULL, NULL, '2026-02-02 10:13:45', '2026-02-02 10:13:45', 0, 0),
(337, 238, 'خدمة ما بعد البيع', 'متابعة جودة المنتجات وحل أي مشكلة قد تواجه العميل بعد الشراء', 'Maintenance', 'approved', NULL, NULL, NULL, NULL, '2026-02-02 10:13:45', '2026-02-02 10:13:45', 0, 0),
(338, 238, 'استشارات حول المساحات', 'نصائح حول استغلال المساحات الصغيرة والكبيرة بشكل عملي وجمالي', 'Consultation', 'approved', NULL, NULL, NULL, NULL, '2026-02-02 10:13:45', '2026-02-02 10:13:45', 0, 0),
(339, 239, 'تصميم الاثاث', 'محمد أبو سلطان وأولاده للاثاث تُعد من أبرز الأسماء في عالم الأثاث، حيث تجمع بين الخبرة العائلية الطويلة والابتكار العصري لتقديم منتجات عالية الجودة تناسب مختلف الأذواق. يختص المعرض بتصميم وتنفيذ غرف النوم، غرف الجلوس، الصالونات، المطابخ، إضافة إلى الكنب والسفرة، مع إمكانية التفصيل حسب رغبة الزبون من حيث الألوان، الأحجام، والخامات. كما يوفر خدمات متكاملة تشمل التوصيل، التركيب، وخدمة ما بعد البيع لضمان راحة ورضا العملاء. بفضل التزامه بالجودة واهتمامه بأدق التفاصيل، أصبح اسم محمد أبو سلطان وأولاده', 'Design', 'approved', NULL, NULL, NULL, NULL, '2026-02-02 10:38:32', '2026-02-02 10:38:32', 0, 0),
(340, 239, 'تصنيع الاثاث', 'مفروشات محمد أبو سلطان وأولاده تُعرف بأنها متخصصة في صناعة الأثاث بجودة عالية وتصاميم متنوعة تناسب جميع الأذواق. يتميز المعرض بالجمع بين الحرفية التقليدية واللمسات العصرية، ليقدم منتجات متينة وأنيقة تشمل غرف النوم، غرف الجلوس، الصالونات، المطابخ، والكنب، مع إمكانية التفصيل حسب رغبة الزبون. بفضل خبرته الطويلة واهتمامه بأدق التفاصيل، أصبح اسم محمد أبو سلطان وأولاده عنوانًا للثقة والتميز في عالم الأثاث، حيث يقدم حلولًا متكاملة من التصميم إلى التصنيع والتوصيل والتركيب.', 'Manufacturing', 'approved', NULL, NULL, NULL, NULL, '2026-02-02 10:38:32', '2026-02-02 10:38:32', 0, 0),
(341, 239, 'خدمة عملاء', 'محلات محمد أبو سلطان وأولاده للأثاث تتوفر خدمة عملاء مميزة تهدف إلى تلبية احتياجات الزبائن وضمان رضاهم في كل مرحلة من مراحل التعامل. يعمل فريق خدمة العملاء على تقديم الاستشارات قبل الشراء لمساعدة الزبون في اختيار الأثاث المناسب، كما يتابع عملية الشراء خطوة بخطوة لتوفير تجربة سلسة ومريحة. ولا يتوقف الأمر عند ذلك، بل تمتد الخدمة لتشمل ما بعد البيع من خلال متابعة التوصيل والتركيب والرد على أي استفسارات أو ملاحظات، مما يعكس حرص المحل على بناء علاقة ثقة طويلة الأمد مع عملائه. بفضل هذا الاهتمام، أصبحت', 'Other', 'approved', NULL, NULL, NULL, NULL, '2026-02-02 10:38:32', '2026-02-02 10:38:32', 0, 0),
(342, 240, 'ffgdfg', 'dsfgdsgfd', 'Material Specification', 'approved', NULL, NULL, NULL, NULL, '2026-02-02 16:06:39', '2026-02-02 16:06:39', 0, 0),
