INSERT INTO `tenders` (`id`, `external_id`, `external_source`, `title`, `short_description`, `description`, `publisher`, `company_name`, `company_url`, `publisher_type`, `published_date`, `deadline`, `source_url`, `category`, `budget`, `location`, `locations`, `status`, `requirements`, `active`, `created_at`, `updated_at`, `views_count`, `is_visible`) VALUES
(14, '13441', 'jobs.ps', 'توريد وتركيب أثاث مكتبي  لوحدة التنظير ولقسم غسيل الكلى لمستشفى المطلع', '&nbsp;إعلان طرح عطاء – توريد وتركيب أثاث مكتبي لوحدة التنظير ولقسم غسيل الكلىلمستشفى المطلع -الاتحاد اللوثري العالمي في القدسيُعلن الاتحاد اللوثري العالمي – مستشفى المطلع عن طرح عطاء \" توريد وتركيب أثاث مكتبي لوحدة التنظير ولقسم غسيل الكلى بتمويل من الاتحاد الأوروبي وينفذ عن طريق برنامج الأمم المتحدة الإنمائي (UNDP) وذلك وفقًا للشروط والمواصفات الفنية الواردة في وثائق العطاء.على الشركات المتخصصة والراغبة في المشاركة، والتي تمتلك الخبرة الكافية في هذا المجال، التقدم بطلب الحصول على وثائق العطاء عبر إرسال طلب رسمي إلى البريد الإلكتروني:dayyad@avh.orgسيتم توفير وثائق العطاء ابتداءً من يوم الثلاثاء الموافق 13/1/2026 وحتى يوم الثلاثاء الموافق 20/1/2026.آخر موعد لتقديم...', '&nbsp;إعلان طرح عطاء – توريد وتركيب أثاث مكتبي لوحدة التنظير ولقسم غسيل الكلىلمستشفى المطلع -الاتحاد اللوثري العالمي في القدسيُعلن الاتحاد اللوثري العالمي – مستشفى المطلع عن طرح عطاء \" توريد وتركيب أثاث مكتبي لوحدة التنظير ولقسم غسيل الكلى بتمويل من الاتحاد الأوروبي وينفذ عن طريق برنامج الأمم المتحدة الإنمائي (UNDP) وذلك وفقًا للشروط والمواصفات الفنية الواردة في وثائق العطاء.على الشركات المتخصصة والراغبة في المشاركة، والتي تمتلك الخبرة الكافية في هذا المجال، التقدم بطلب الحصول على وثائق العطاء عبر إرسال طلب رسمي إلى البريد الإلكتروني:dayyad@avh.orgسيتم توفير وثائق العطاء ابتداءً من يوم الثلاثاء الموافق 13/1/2026 وحتى يوم الثلاثاء الموافق 20/1/2026.آخر موعد لتقديم...', 'Augusta Victoria Hospital / مستشفى المُطّلع', 'Augusta Victoria Hospital / مستشفى المُطّلع', 'https://jobs.ps/employers/augusta-victoria-hospital', 'other', '2026-01-25', '2026-02-03', 'https://jobs.ps/tenders/undp-29-13441.html', NULL, NULL, 'القدس', '[\"القدس\"]', 'Closing Soon', NULL, 1, '2026-01-25 06:24:24', '2026-02-03 23:28:57', 11, 1),
(13, '13268', 'jobs.ps', 'توريد فرش منزلي', 'إعلان استدراج عروض أسعارتوريد فرش منزلي – منظمة قرى الأطفال SOS – فلسطينتعلن منظمة قرى الأطفال SOS – فلسطين عن رغبتها في استدراج عروض أسعار من الموردين والشركات المتخصصة لتوريد فرش منزلي لصالح قرية الأطفال SOS – بيت لحم، وذلك وفقًا للمواصفات والكميات والشروط الواردة في طلب عرض الأسعار (RFQ) التالي:عرض سعر فرش منزلي 2025.pdfنطاق التوريد يشمل:مخداتكُفَر شتويةحرامات شتويةبراديسجاددعسات حماموذلك حسب المواصفات الفنية والكميات المحددة في كراسة الاستدراج.آخر موعد لتقديم العروض: 25-12-2025 الساعة 12 ظهرافي مقر منظمة قرى الأطفال SOS – فلسطينبيت لحم – الكركفة – شارع هيرمان جماينرأو عبر البريد الإلكتروني:&nbsp;mohammed.laham@sos-palestine.orgشروط عامة:تقديم عرض سعر مختوم وموقع حسب الأصول.الأسعار بالشيكل...', '<p>إعلان استدراج عروض أسعارتوريد فرش منزلي – منظمة قرى الأطفال SOS – فلسطينتعلن منظمة قرى الأطفال SOS – فلسطين عن رغبتها في استدراج عروض أسعار من الموردين والشركات المتخصصة لتوريد فرش منزلي لصالح قرية الأطفال SOS – بيت لحم، وذلك وفقًا للمواصفات والكميات والشروط الواردة في طلب عرض الأسعار (RFQ) التالي:عرض سعر فرش منزلي 2025.pdfنطاق التوريد يشمل:مخداتكُفَر شتويةحرامات شتويةبراديسجاددعسات حماموذلك حسب المواصفات الفنية والكميات المحددة في كراسة الاستدراج.آخر موعد لتقديم العروض: 25-12-2025 الساعة 12 ظهرافي مقر منظمة قرى الأطفال SOS – فلسطينبيت لحم – الكركفة – شارع هيرمان جماينرأو عبر البريد الإلكتروني:&nbsp;mohammed.laham@sos-palestine.orgشروط عامة:تقديم عرض سعر مختوم وموقع حسب الأصول.الأسعار بالشيكل...</p>', 'قرى الأطفال SOS Children’s Villages', 'قرى الأطفال SOS Children’s Villages ', 'https://jobs.ps/employers/sosvillagespalestine', 'other', '2026-01-25', '2025-12-25', 'https://jobs.ps/tenders/توريد-فرش-منزلي-13268.html', '', '', 'بيت لحم', '[\"بيت لحم\"]', 'Closed', NULL, 1, '2026-01-25 06:24:21', '2026-02-14 00:27:59', 23, 1),
(15, '13484', 'jobs.ps', 'توريد وتركيب اثاث مكتبي ومدرسي', '&nbsp;إعلان طرح عطاءتوريد وتركيب اثاث مكتبي ومدرسي ضمن مشروع تطوير وتأهيل مختبرات ستيم (STEM)رقم : 6-TA-STM-FUR-2024تعلن مؤسسة التعاون عن طرح عطاء توريد وتركيب اثاث مكتبي ومدرسي ضمن مشروع تطوير وتأهيل مختبرات ستيم (STEM) &nbsp; &nbsp;&nbsp;لمدارس &nbsp;مختارة في محافظات الضفة الغربية، والممول من الصندوق العربي للإنماء الاقتصادي والاجتماعي. على الشركات الراغبة في التقدم للعطاء &nbsp;الأخذ بعين الاعتبار الشروط التالية:يشترط أن تكون الجهة المتقدمة للعطاء جهة مسجّلة رسميًا وتمتلك خبرة موثقة في الأعمال ذات الصلة وبما يتناسب مع طبيعة التوريدات المطلوب تنفيذها.الأسعار بالدولار غير شاملة ضريبة القيمة المضافة ، المشروع معفي من الضريبةأن تمتلك الشركة المقدرة الفنية، المالية، واللوجستية الموثقة لتنفيذ الاعمال...', '&nbsp;إعلان طرح عطاءتوريد وتركيب اثاث مكتبي ومدرسي ضمن مشروع تطوير وتأهيل مختبرات ستيم (STEM)رقم : 6-TA-STM-FUR-2024تعلن مؤسسة التعاون عن طرح عطاء توريد وتركيب اثاث مكتبي ومدرسي ضمن مشروع تطوير وتأهيل مختبرات ستيم (STEM) &nbsp; &nbsp;&nbsp;لمدارس &nbsp;مختارة في محافظات الضفة الغربية، والممول من الصندوق العربي للإنماء الاقتصادي والاجتماعي. على الشركات الراغبة في التقدم للعطاء &nbsp;الأخذ بعين الاعتبار الشروط التالية:يشترط أن تكون الجهة المتقدمة للعطاء جهة مسجّلة رسميًا وتمتلك خبرة موثقة في الأعمال ذات الصلة وبما يتناسب مع طبيعة التوريدات المطلوب تنفيذها.الأسعار بالدولار غير شاملة ضريبة القيمة المضافة ، المشروع معفي من الضريبةأن تمتلك الشركة المقدرة الفنية، المالية، واللوجستية الموثقة لتنفيذ الاعمال...', 'Welfare Association - Taawon  مؤسسة التعاون', 'Welfare Association - Taawon  مؤسسة التعاون', 'https://jobs.ps/employers/taawonpalestine', 'other', '2026-01-25', '2026-01-25', 'https://jobs.ps/tenders/6-ta-stm-fur-2024-13484.html', NULL, NULL, 'رام الله والبيرة', '[\"رام الله والبيرة\"]', 'Closed', NULL, 1, '2026-01-25 06:24:25', '2026-02-03 08:03:39', 9, 1),
(16, '13494', 'jobs.ps', ' Provision of cabinets and shelving units for the Palestinian Land Authority', 'ObjectivesUN-Habitat, with funding from the European Union, is implementing the project “Scaling Up Community-Driven Processes of Mapping of Land Rights and Land Use Planning in the West Bank, including Area C.” This project aims to enhance the resilience of Palestinian communities by improving land tenure security, supporting inclusive spatial planning, and strengthening institutional capacities in land governance and service delivery.As part of this effort, UN-Habitat is supporting the Palestinian Land Authority (PLA) to modernize and safeguard its archives. The PLA’s archives department, located in the ministerial compound building, is responsible for collecting, storing, and managing all official documentation from settlement...', 'ObjectivesUN-Habitat, with funding from the European Union, is implementing the project “Scaling Up Community-Driven Processes of Mapping of Land Rights and Land Use Planning in the West Bank, including Area C.” This project aims to enhance the resilience of Palestinian communities by improving land tenure security, supporting inclusive spatial planning, and strengthening institutional capacities in land governance and service delivery.As part of this effort, UN-Habitat is supporting the Palestinian Land Authority (PLA) to modernize and safeguard its archives. The PLA’s archives department, located in the ministerial compound building, is responsible for collecting, storing, and managing all official documentation from settlement...', 'UN-Habitat ', 'UN-Habitat ', 'https://jobs.ps/employers/un-habitat', 'other', '2026-01-25', '2026-01-29', 'https://jobs.ps/tenders/provision-of-cabinets-and-shelving-units-13494.html', NULL, NULL, 'رام الله والبيرة', '[\"رام الله والبيرة\"]', 'Closing Soon', NULL, 1, '2026-01-25 06:24:26', '2026-02-19 14:50:32', 14, 1),
(17, '13581', 'jobs.ps', 'تأهيل موردين / مزودي خدمات/ شركات استشارية / مقاولين لعام 2026', 'طلب إبداء الاهتمام رقم: 2026/001يدعوكم صندوق الاستثمار الفلسطيني وشركاته التابعة، الى التقدم بعرض إبداء الاهتمام لتأهيل الموردين\\مزودي الخدمة\\الشركات الاستشارية\\المقاولين.يمكن للشركات المعنية الحصول...', 'طلب إبداء الاهتمام رقم: 2026/001يدعوكم صندوق الاستثمار الفلسطيني وشركاته التابعة، الى التقدم بعرض إبداء الاهتمام لتأهيل الموردين\\مزودي الخدمة\\الشركات الاستشارية\\المقاولين.يمكن للشركات المعنية الحصول على وثائق إبداء الاهتمام ومعلومات اضافية من دائرة العطاءات والمشتريات على البريد الإلكتروني e-procurement@pif.psسيتم تأهيل الموردين\\مزودي الخدمة\\الشركات الاستشارية\\المقاولين في المجالات التالية كما هو موضح أدناه:الشركة غير ملزمة بأي تعاقد أو قبول أي عرض، ولا يمنح تقديم إبداء الاهتمام أي حق أو امتياز لمقدمها.سيتم تأهيل الموردين\\مزودي الخدمة\\الشركات الاستشارية\\المقاولين بناء على الخبرة والمؤهلات المبينة في وثائق إبداء الاهتمام.يتم تقديم عروض إبداء الاهتمام كما هو مبين في وثيقة إبداء الاهتمام بالإضافة إلى تقديم الوثائق الداعمة من الموردين\\مزودي الخدمة\\الاستشاريين\\المقاولين الراغبين في التقديم...', 'Palestine Investment Fund', 'Palestine Investment Fund', 'https://jobs.ps/employers/pif', 'other', '2026-01-29', '2026-02-15', 'https://jobs.ps/tenders/تأهيل-موردين-26-13581.html', NULL, NULL, 'رام الله والبيرة, القدس, قطاع غزة, بيت لحم, الخليل, أريحا, نابلس, جنين, طوباس, قلقيلية, سلفيت وبديا, طولكرم, بيرزيت, روابي, ابو ديس, العيزرية, الرام, حزما, عناتا, كفر عقب, بدُو', '[\"رام الله والبيرة\", \"القدس\", \"قطاع غزة\", \"بيت لحم\", \"الخليل\", \"أريحا\", \"نابلس\", \"جنين\", \"طوباس\", \"قلقيلية\", \"سلفيت وبديا\", \"طولكرم\", \"بيرزيت\", \"روابي\", \"ابو ديس\", \"العيزرية\", \"الرام\", \"حزما\", \"عناتا\", \"كفر عقب\", \"بدُو\"]', 'Open', NULL, 1, '2026-01-27 11:10:00', '2026-02-04 13:45:37', 4, 1),
(18, '13440', 'jobs.ps', 'تأهيل موردين لعام 2026', 'جمعية الاغاثة الطبية الفلسطينية هي واحدة من اكبر المنظمات الصحية والمجتمعية الغير ربحية تأسست في عام 1979 من قبل مجموعة من الاطباء الفلسطينيين والعاملين في مجال الصحة بهدف التصدي لتدهور الاوضاع...', 'جمعية الاغاثة الطبية الفلسطينية هي واحدة من اكبر المنظمات الصحية والمجتمعية الغير ربحية تأسست في عام 1979 من قبل مجموعة من الاطباء الفلسطينيين والعاملين في مجال الصحة بهدف التصدي لتدهور الاوضاع الصحية بسبب سنوات من الاحتلال الاسرائيلي ، تركز برامج جمعية الاغاثة الطبية على الوقاية والتمكين والمشاركة المجتمعية وتمكين المواطن ، وفي الوقت نفسة تسعى الاغاثة الطبية الى بناء نماذج التنمية الصحية لتلبية احتياجات القطاعات الاكثر فقرا وتهميشا في فلسطين .تقدم الجمعية خدماتها في الضفة الغربية والقدس وقطاع غزةترغب جمعية الاغاثة الطبية في تحديث قاعدة بيانات الموردين المعتمدين لديها في توفير الاحتياجات التالية :ادويةمواد مخبريةمستلزمات طبية وصحيةاجهزة طبيةحقائب اسعاف اولياجهزة...', 'جمعية الاغاثة الطبية الفلسطينية', 'جمعية الاغاثة الطبية الفلسطينية', 'https://jobs.ps/employers/pmrs', 'other', '2026-02-02', '2026-01-20', 'https://jobs.ps/tenders/تأهيل-موردين-25-13440.html', NULL, NULL, 'رام الله والبيرة', '[\"رام الله والبيرة\"]', 'Closed', NULL, 1, '2026-02-02 18:44:15', '2026-02-07 12:36:39', 3, 1),
(19, '13760', 'jobs.ps', 'مناقصة توريد نقطة اتصال ومساعدة (كشك خشبي)ضمن مواقع النزوح في مواصي خانيونس .', 'إعلان بيع مناقصه عطاء رقم (4/2026)تأسس المجلس الفلسطيني للإسكان عام 1991 في مدينـة القدس كمؤسسة غير ربحية، تهدف إلى تطوير قطاع الإسـكان والمساهمة في حل مشاكل الإسـكان التي تفاقمت نتيجة للوضع...', 'إعلان بيع مناقصه عطاء رقم (4/2026)تأسس المجلس الفلسطيني للإسكان عام 1991 في مدينـة القدس كمؤسسة غير ربحية، تهدف إلى تطوير قطاع الإسـكان والمساهمة في حل مشاكل الإسـكان التي تفاقمت نتيجة للوضع الاقتصادي والسـياسي المتردي في الأراضي الفلسطينية. واستطاع المجلس خلال عمله تجنيد أكثر من (260) مليون دولار للمساهمة في حل مشكلة السكن في فلسطين استفادت منها حوالي (12) ألف عائلة فلسطينية عن طريق برامج ومشاريع المجلس المختلفة، وساهم المجلس في إعداد الخطط والاستراتيجيات والدراسات في مجال الإسكان للمساهمة في حل مشكلة الإسكان المتراكمة بسبب الظروف السياسية غير المستقرة. وحيث أن المجلس يعمل حالياً في مجال الإغاثة والطوارئ ضمن مشروع إدارة...', 'المجلس الفلسطيني للاسكان', 'المجلس الفلسطيني للاسكان', 'https://jobs.ps/employers/phcgaza', 'other', '2026-02-16', '2026-02-16', 'https://jobs.ps/tenders/مناقصة-توريد-نقطة-اتصال-ومساعدة-كشك-خشبي-13760.html', NULL, NULL, 'قطاع غزة', '[\"قطاع غزة\"]', 'Closed', NULL, 1, '2026-02-16 05:39:18', '2026-02-18 10:23:14', 1, 1),
(20, '13829', 'jobs.ps', 'توفير مواد لمساحات اللعب والتعلم المتنقلة في قطاع غزة، فلسطين - Materials to Mobile Play and Learning Species', 'INTERNATIONAL RESCUE COMMITTEE (IRC)Request for ProposalsMaterials to Mobile Play and Learning Species in Gaza Strip, PalestineIRC Reference# : IRC/RFP/OPT/2026_04The International Rescue Committee...', 'INTERNATIONAL RESCUE COMMITTEE (IRC)Request for ProposalsMaterials to Mobile Play and Learning Species in Gaza Strip, PalestineIRC Reference# : IRC/RFP/OPT/2026_04The International Rescue Committee (IRC) is an international, nonsectarian, voluntary organization providing relief and protection for refugees and victims of oppression or violent conflict. IRC responds to the world’s worst humanitarian crises and helps people to survive and rebuild their lives. Founded in 1933, the IRC offers lifesaving care and life-changing assistance to refugees forced to flee from war or disaster.The IRC operates in Occupied Palestinian Territory and has a requirement to establish a tender bid to provide Materials to Mobile Play...', 'International Rescue Committee', 'International Rescue Committee', 'https://jobs.ps/employers/irc', 'other', '2026-02-19', '2026-03-07', 'https://jobs.ps/tenders/irc-rfp-opt-2026-04-13829.html', NULL, NULL, 'قطاع غزة', '[\"قطاع غزة\"]', 'Open', NULL, 1, '2026-02-19 07:10:49', '2026-02-19 23:01:19', 1, 1);
