CREATE DEFINER=`technopark`@`localhost` PROCEDURE `cleanup_expired_verifications` ()   BEGIN
    DELETE FROM email_verifications WHERE is_verified = 0 AND expires_at < NOW();
    DELETE FROM email_verifications WHERE is_verified = 1 AND verified_at < DATE_SUB(NOW(), INTERVAL 7 DAY)
        AND email NOT IN (SELECT email FROM designers);
    SELECT 'Cleanup completed' as status, ROW_COUNT() as records_deleted;
END$$

CREATE DEFINER=`technopark`@`localhost` PROCEDURE `safe_add_column` (IN `table_name` VARCHAR(64), IN `column_name` VARCHAR(64), IN `column_definition` TEXT)   BEGIN
        DECLARE column_exists INT DEFAULT 0;

        SELECT COUNT(*) INTO column_exists
        FROM information_schema.COLUMNS
        WHERE TABLE_SCHEMA = DATABASE()
        AND TABLE_NAME = table_name
        AND COLUMN_NAME = column_name;

        IF column_exists = 0 THEN
            SET @sql = CONCAT('ALTER TABLE ', table_name, ' ADD COLUMN ', column_name, ' ', column_definition);
            PREPARE stmt FROM @sql;
            EXECUTE stmt;
            DEALLOCATE PREPARE stmt;
            SELECT CONCAT('✓ Added column: ', table_name, '.', column_name) as status;
        ELSE
            SELECT CONCAT('○ Column already exists: ', table_name, '.', column_name) as status;
        END IF;
    END$$

DELIMITER ;

